HYPOTHESIS_000001_AUTOGLUON_001_PY_F3ED504849_SOURCE = 'import numpy as np\nimport pandas as pd\n\n\ndef _safe_subtract(raw: pd.DataFrame, left: str, right: str) -> pd.Series:\n    left_col = raw[left]\n    right_col = raw[right]\n    valid = np.isfinite(left_col) & np.isfinite(right_col)\n    result = pd.Series(np.nan, index=raw.index, dtype=float)\n    result.loc[valid] = left_col.loc[valid] - right_col.loc[valid]\n    return result\n\n\ndef add_broadband_color_shape(raw, deps, aux):\n    u = raw["u"]\n    g = raw["g"]\n    r = raw["r"]\n    i = raw["i"]\n    z = raw["z"]\n\n    color_u_g = _safe_subtract(raw, "u", "g")\n    color_g_r = _safe_subtract(raw, "g", "r")\n    color_r_i = _safe_subtract(raw, "r", "i")\n    color_i_z = _safe_subtract(raw, "i", "z")\n    color_u_r = _safe_subtract(raw, "u", "r")\n    color_g_i = _safe_subtract(raw, "g", "i")\n    color_r_z = _safe_subtract(raw, "r", "z")\n    color_u_z = _safe_subtract(raw, "u", "z")\n\n    curve_ugr = pd.Series(np.nan, index=raw.index, dtype=float)\n    curve_ugr_valid = np.isfinite(u) & np.isfinite(g) & np.isfinite(r)\n    curve_ugr.loc[curve_ugr_valid] = u.loc[curve_ugr_valid] - 2.0 * g.loc[curve_ugr_valid] + r.loc[curve_ugr_valid]\n\n    curve_gri = pd.Series(np.nan, index=raw.index, dtype=float)\n    curve_gri_valid = np.isfinite(g) & np.isfinite(r) & np.isfinite(i)\n    curve_gri.loc[curve_gri_valid] = g.loc[curve_gri_valid] - 2.0 * r.loc[curve_gri_valid] + i.loc[curve_gri_valid]\n\n    curve_riz = pd.Series(np.nan, index=raw.index, dtype=float)\n    curve_riz_valid = np.isfinite(r) & np.isfinite(i) & np.isfinite(z)\n    curve_riz.loc[curve_riz_valid] = r.loc[curve_riz_valid] - 2.0 * i.loc[curve_riz_valid] + z.loc[curve_riz_valid]\n\n    return pd.DataFrame(\n        {\n            "color_u_g": color_u_g,\n            "color_g_r": color_g_r,\n            "color_r_i": color_r_i,\n            "color_i_z": color_i_z,\n            "color_u_r": color_u_r,\n            "color_g_i": color_g_i,\n            "color_r_z": color_r_z,\n            "color_u_z": color_u_z,\n            "curve_ugr": curve_ugr,\n            "curve_gri": curve_gri,\n            "curve_riz": curve_riz,\n        },\n        index=raw.index,\n    )\n\n\nFEATURE_GROUPS = [\n    {\n        "name": "broadband_color_shape",\n        "fn": add_broadband_color_shape,\n        "depends_on": [],\n        "description": "Create broadband color and curvature features from ugriz magnitudes.",\n    }\n]\n'

HYPOTHESIS_000003_AUTOGLUON_002_PY_1DE6FF1BE7_SOURCE = 'import numpy as np\nimport pandas as pd\n\ndef add_galactic_sightline_context(raw, deps, aux):\n    alpha_rad = np.deg2rad((pd.to_numeric(raw["alpha"], errors="coerce") % 360.0).to_numpy(dtype=float))\n    delta_rad = np.deg2rad(pd.to_numeric(raw["delta"], errors="coerce").to_numpy(dtype=float))\n\n    # Equatorial unit-sphere coordinates (wrap-safe via alpha modulo 360)\n    cos_delta = np.cos(delta_rad)\n    x_eq = cos_delta * np.cos(alpha_rad)\n    y_eq = cos_delta * np.sin(alpha_rad)\n    z_eq = np.sin(delta_rad)\n\n    # J2000 equatorial -> Galactic rotation matrix\n    x_gal = (\n        -0.0548755604 * x_eq\n        + -0.8734370902 * y_eq\n        + -0.4838350155 * z_eq\n    )\n    y_gal = (\n        0.4941094279 * x_eq\n        + -0.4448296300 * y_eq\n        + 0.7469822445 * z_eq\n    )\n    z_gal = (\n        -0.8676661490 * x_eq\n        + -0.1980763734 * y_eq\n        + 0.4559837762 * z_eq\n    )\n\n    z_clip = np.clip(z_gal, -1.0, 1.0)\n    b_rad = np.arcsin(z_clip)\n    b_deg = np.degrees(b_rad)\n    abs_b_deg = np.abs(b_deg)\n\n    l_rad = np.arctan2(y_gal, x_gal)\n    l_deg = np.degrees(l_rad) % 360.0\n    l_rad = np.deg2rad(l_deg)\n\n    sin_l = np.sin(l_rad)\n    cos_l = np.cos(l_rad)\n    sin_b = np.sin(b_rad)\n    cos_b = np.cos(b_rad)\n\n    dist_to_galactic_center = np.degrees(np.arccos(np.clip(x_gal, -1.0, 1.0)))\n    dist_to_galactic_anticenter = np.degrees(np.arccos(np.clip(-x_gal, -1.0, 1.0)))\n    dist_to_north_galactic_pole = np.degrees(np.arccos(np.clip(z_gal, -1.0, 1.0)))\n    dist_to_south_galactic_pole = np.degrees(np.arccos(np.clip(-z_gal, -1.0, 1.0)))\n\n    b_band_edges = (0.0, 10.0, 20.0, 35.0, 50.0, 70.0, 90.0000001)\n    b_band_labels = ("0-10", "10-20", "20-35", "35-50", "50-70", "70-90")\n    b_band = pd.cut(\n        abs_b_deg,\n        bins=b_band_edges,\n        labels=b_band_labels,\n        right=False,\n        include_lowest=True,\n    )\n\n    l_sector_edges = tuple(np.arange(0.0, 390.0, 30.0))\n    l_sector_labels = tuple(f"{int(start):03d}-{int(start + 30):03d}" for start in l_sector_edges[:-1])\n    l_sector = pd.cut(\n        l_deg,\n        bins=l_sector_edges,\n        labels=l_sector_labels,\n        right=False,\n        include_lowest=True,\n    )\n\n    b_band_str = b_band.astype(str)\n    l_sector_str = l_sector.astype(str)\n    crossed_regime = b_band_str + "|" + l_sector_str\n\n    return pd.DataFrame(\n        {\n            "eq_x": x_eq,\n            "eq_y": y_eq,\n            "eq_z": z_eq,\n            "gal_l_deg": l_deg,\n            "gal_b_deg": b_deg,\n            "gal_abs_b_deg": abs_b_deg,\n            "gal_sin_l": sin_l,\n            "gal_cos_l": cos_l,\n            "gal_sin_b": sin_b,\n            "gal_cos_b": cos_b,\n            "gal_plane_angular_distance_deg": abs_b_deg,\n            "gal_dist_to_galactic_center_deg": dist_to_galactic_center,\n            "gal_dist_to_galactic_anticenter_deg": dist_to_galactic_anticenter,\n            "gal_dist_to_north_pole_deg": dist_to_north_galactic_pole,\n            "gal_dist_to_south_pole_deg": dist_to_south_galactic_pole,\n            "gal_b_band": b_band_str,\n            "gal_l_sector": l_sector_str,\n            "gal_b_band_l_sector": crossed_regime,\n        },\n        index=raw.index,\n    )\n\nFEATURE_GROUPS = [\n    {\n        "name": "galactic_sightline_context",\n        "fn": add_galactic_sightline_context,\n        "depends_on": [],\n        "description": "Create Galactic coordinate-derived spatial features including smooth angular encodings, center/pole distances, and coarse latitude-longitude regime bins.",\n    }\n]'

HYPOTHESIS_000007_AUTOGLUON_001_PY_FAF846A6C6_SOURCE = 'import numpy as np\nimport pandas as pd\n\n\ndef _fill_zero_signs(sign_paths: np.ndarray) -> np.ndarray:\n    filled = sign_paths.copy()\n    for i in range(filled.shape[0]):\n        row = filled[i]\n        nonzero_idx = np.flatnonzero(row)\n        if nonzero_idx.size == 0:\n            continue\n        for j in range(row.size):\n            if row[j] == 0:\n                nearest = nonzero_idx[np.argmin(np.abs(nonzero_idx - j))]\n                row[j] = row[nearest]\n        filled[i] = row\n    return filled\n\n\ndef add_band_order_topology(raw, deps, aux):\n    bands = ["u", "g", "r", "i", "z"]\n    mags = raw[bands].astype(float)\n\n    ranks_df = mags.rank(axis=1, method="first", ascending=True).astype(np.int8)\n    ranks = ranks_df.to_numpy(dtype=np.int8)\n\n    band_to_idx = {"u": 0, "g": 1, "r": 2, "i": 3, "z": 4}\n    brightest_idx = ranks_df.idxmin(axis=1).map(band_to_idx).astype(np.int8)\n    faintest_idx = ranks_df.idxmax(axis=1).map(band_to_idx).astype(np.int8)\n\n    upper_mask = np.triu(np.ones((5, 5), dtype=bool), k=1)\n    inv_total = (ranks[:, :, None] > ranks[:, None, :])[:, upper_mask].sum(axis=1).astype(np.int8)\n    inv_vs_increasing = inv_total.copy()\n    inv_vs_decreasing = (10 - inv_total).astype(np.int8)\n\n    eps = 0.02\n    d1 = mags["g"].to_numpy() - mags["u"].to_numpy()\n    d2 = mags["r"].to_numpy() - mags["g"].to_numpy()\n    d3 = mags["i"].to_numpy() - mags["r"].to_numpy()\n    d4 = mags["z"].to_numpy() - mags["i"].to_numpy()\n    diffs = np.column_stack((d1, d2, d3, d4))\n\n    signs = np.zeros_like(diffs, dtype=np.int8)\n    signs[diffs > eps] = 1\n    signs[diffs < -eps] = -1\n    signs = _fill_zero_signs(signs)\n\n    sign_changes_mask = signs[:, :-1] != signs[:, 1:]\n    sign_change_count = sign_changes_mask.sum(axis=1).astype(np.int8)\n    sign_monotone = (sign_change_count == 0).astype(np.int8)\n    sign_one_change = (sign_change_count == 1).astype(np.int8)\n    sign_first_change_pos = np.where(\n        sign_changes_mask.any(axis=1),\n        sign_changes_mask.argmax(axis=1).astype(np.int8) + 1,\n        0,\n    ).astype(np.int8)\n\n    flat = (mags.max(axis=1) - mags.min(axis=1)) <= eps\n    flat_np = flat.to_numpy()\n\n    inv_total = np.where(flat_np, 0, inv_total)\n    inv_vs_increasing = np.where(flat_np, 0, inv_vs_increasing)\n    inv_vs_decreasing = np.where(flat_np, 0, inv_vs_decreasing)\n    sign_change_count = np.where(flat_np, 0, sign_change_count)\n    sign_monotone = np.where(flat_np, 1, sign_monotone)\n    sign_one_change = np.where(flat_np, 0, sign_one_change)\n    sign_first_change_pos = np.where(flat_np, 0, sign_first_change_pos)\n\n    sign_monotone = sign_monotone.astype(np.int8)\n    sign_one_change = sign_one_change.astype(np.int8)\n    sign_change_count = sign_change_count.astype(np.int8)\n    sign_first_change_pos = sign_first_change_pos.astype(np.int8)\n    inv_total = inv_total.astype(np.int8)\n    inv_vs_increasing = inv_vs_increasing.astype(np.int8)\n    inv_vs_decreasing = inv_vs_decreasing.astype(np.int8)\n\n    flat_topology = flat.astype(np.int8)\n    bright_interior = brightest_idx.isin([1, 2, 3]).astype(np.int8)\n    bright_edge = brightest_idx.isin([0, 4]).astype(np.int8)\n    faint_interior = faintest_idx.isin([1, 2, 3]).astype(np.int8)\n    faint_edge = faintest_idx.isin([0, 4]).astype(np.int8)\n\n    return pd.DataFrame(\n        {\n            "rank_u": ranks_df["u"],\n            "rank_g": ranks_df["g"],\n            "rank_r": ranks_df["r"],\n            "rank_i": ranks_df["i"],\n            "rank_z": ranks_df["z"],\n            "brightest_band_wl_idx": brightest_idx,\n            "faintest_band_wl_idx": faintest_idx,\n            "flat_topology": flat_topology,\n            "inversion_count": inv_total,\n            "inversion_count_vs_increasing": inv_vs_increasing,\n            "inversion_count_vs_decreasing": inv_vs_decreasing,\n            "sign_d1": pd.Series(signs[:, 0], index=raw.index, dtype=np.int8),\n            "sign_d2": pd.Series(signs[:, 1], index=raw.index, dtype=np.int8),\n            "sign_d3": pd.Series(signs[:, 2], index=raw.index, dtype=np.int8),\n            "sign_d4": pd.Series(signs[:, 3], index=raw.index, dtype=np.int8),\n            "sign_monotone": sign_monotone,\n            "sign_change_count": sign_change_count,\n            "sign_exactly_one_change": sign_one_change,\n            "sign_first_change_pos": sign_first_change_pos,\n            "brightest_band_interior": bright_interior,\n            "brightest_band_edge": bright_edge,\n            "faintest_band_interior": faint_interior,\n            "faintest_band_edge": faint_edge,\n        },\n        index=raw.index,\n    )\n\n\nFEATURE_GROUPS = [\n    {\n        "name": "band_order_topology",\n        "fn": add_band_order_topology,\n        "depends_on": [],\n        "description": "Encodes ugriz brightness-order topology via per-row band ranks, inversion statistics, monotone sign-path transitions, and edge/interior bright/faint band positions.",\n    }\n]'

HYPOTHESIS_000016_AUTOGLUON_002_PY_CA20FB0445_SOURCE = 'import numpy as np\nimport pandas as pd\n\n_PI = 3.141592653589793\n_FULL_CIRCLE_DEG = 360.0\n_FULL_CIRCLE_RAD = 2.0 * _PI\n_HALF_CIRCLE_RAD = _PI\n_SDSS_STRIPE_WIDTH_DEG = 2.5\n_SDSS_STRIPE_HALF_WIDTH_DEG = _SDSS_STRIPE_WIDTH_DEG / 2.0\n_EPS = 1e-12\n\n_EQ_TO_GAL_MATRIX = (\n    (-0.0548755604, 0.4941094279, -0.8676661490),\n    (-0.8734370902, -0.4448296300, -0.1980763734),\n    (-0.4838350155, 0.7469822445, 0.4559837762),\n)\n\n_SDSS_X_AXIS = (185.0, 32.5)\n_SDSS_V_AXIS = (275.0, 0.0)\n\n\ndef _to_finite(values, default=0.0):\n    return np.nan_to_num(np.asarray(values, dtype=float), nan=default, posinf=default, neginf=default)\n\n\ndef _normalize_rows(vectors, eps=_EPS):\n    vectors = _to_finite(vectors)\n    norm = np.linalg.norm(vectors, axis=1, keepdims=True)\n    denom = np.where(norm > eps, norm, 1.0)\n    return vectors / denom\n\n\ndef _normalize_vector(vector, eps=_EPS):\n    vector = _to_finite(vector)\n    norm = float(np.linalg.norm(vector))\n    if not np.isfinite(norm) or norm <= eps:\n        return np.zeros(3, dtype=float)\n    return vector / norm\n\n\ndef _sph_to_cart(ra_rad, dec_rad):\n    cos_dec = np.cos(dec_rad)\n    x = cos_dec * np.cos(ra_rad)\n    y = cos_dec * np.sin(ra_rad)\n    z = np.sin(dec_rad)\n    return np.column_stack((x, y, z))\n\n\ndef add_sky_frame_position_geometry(raw, deps, aux):\n    idx = raw.index\n    alpha = _to_finite(pd.to_numeric(raw["alpha"], errors="coerce").to_numpy(dtype=float))\n    delta = _to_finite(pd.to_numeric(raw["delta"], errors="coerce").to_numpy(dtype=float))\n\n    alpha_wrapped = np.mod(np.mod(alpha, _FULL_CIRCLE_DEG) + _FULL_CIRCLE_DEG, _FULL_CIRCLE_DEG)\n    delta_clipped = np.clip(delta, -90.0, 90.0)\n\n    alpha_rad = np.radians(alpha_wrapped)\n    delta_rad = np.radians(delta_clipped)\n\n    # Wrap-safe equatorial basis features\n    eq_sin_alpha = _to_finite(np.sin(alpha_rad))\n    eq_cos_alpha = _to_finite(np.cos(alpha_rad))\n    eq_sin_delta = _to_finite(np.sin(delta_rad))\n    eq_cos_delta = _to_finite(np.cos(delta_rad))\n\n    eq_unit = _normalize_rows(_sph_to_cart(alpha_rad, delta_rad))\n    eq_x = _to_finite(eq_unit[:, 0])\n    eq_y = _to_finite(eq_unit[:, 1])\n    eq_z = _to_finite(eq_unit[:, 2])\n\n    # Galactic-frame geometry\n    gal = eq_unit.dot(np.array(_EQ_TO_GAL_MATRIX, dtype=float).T)\n    gx = _to_finite(np.clip(gal[:, 0], -1.0, 1.0))\n    gy = _to_finite(np.clip(gal[:, 1], -1.0, 1.0))\n    gz = _to_finite(np.clip(gal[:, 2], -1.0, 1.0))\n\n    l_raw = np.arctan2(gy, gx)\n    l = _to_finite(np.mod(l_raw + _FULL_CIRCLE_RAD, _FULL_CIRCLE_RAD))\n    b = _to_finite(np.arctan2(gz, np.sqrt(np.clip(gx * gx + gy * gy, 0.0, np.inf))))\n\n    gal_sin_l = _to_finite(np.sin(l))\n    gal_cos_l = _to_finite(np.cos(l))\n    gal_sin_b = _to_finite(np.sin(b))\n    gal_cos_b = _to_finite(np.cos(b))\n    gal_abs_b = _to_finite(np.abs(b))\n    gal_plane_complement = _to_finite(_HALF_CIRCLE_RAD / 2.0 - gal_abs_b)\n\n    gc_arg = np.clip(gal_cos_b * np.cos(l), -1.0, 1.0)\n    anti_arg = np.clip(gal_cos_b * np.cos(l - _PI), -1.0, 1.0)\n    gal_d_gc = _to_finite(np.arccos(gc_arg))\n    gal_d_anticenter = _to_finite(np.arccos(anti_arg))\n\n    # SDSS-frame geometry\n    x_ra_rad = np.radians(np.mod(_SDSS_X_AXIS[0], _FULL_CIRCLE_DEG))\n    x_dec_rad = np.radians(np.clip(_SDSS_X_AXIS[1], -90.0, 90.0))\n    v_ra_rad = np.radians(np.mod(_SDSS_V_AXIS[0], _FULL_CIRCLE_DEG))\n    v_dec_rad = np.radians(np.clip(_SDSS_V_AXIS[1], -90.0, 90.0))\n\n    x_hat = _normalize_vector(\n        np.array(\n            (\n                np.cos(x_dec_rad) * np.cos(x_ra_rad),\n                np.cos(x_dec_rad) * np.sin(x_ra_rad),\n                np.sin(x_dec_rad),\n            ),\n            dtype=float,\n        )\n    )\n    v_hat = _normalize_vector(\n        np.array(\n            (\n                np.cos(v_dec_rad) * np.cos(v_ra_rad),\n                np.cos(v_dec_rad) * np.sin(v_ra_rad),\n                np.sin(v_dec_rad),\n            ),\n            dtype=float,\n        )\n    )\n    z_hat = _normalize_vector(np.cross(x_hat, v_hat))\n    y_hat = _normalize_vector(np.cross(z_hat, x_hat))\n\n    dot_x = _to_finite(eq_unit.dot(x_hat))\n    dot_y = _to_finite(eq_unit.dot(y_hat))\n    dot_z = _to_finite(eq_unit.dot(z_hat))\n\n    eta = _to_finite(np.arcsin(np.clip(dot_z, -1.0, 1.0)))\n    lam = _to_finite(np.arctan2(dot_y, dot_x))\n    lam = _to_finite(np.mod(lam + _PI, _FULL_CIRCLE_RAD) - _PI)\n\n    sdss_sin_eta = _to_finite(np.sin(eta))\n    sdss_cos_eta = _to_finite(np.cos(eta))\n    sdss_sin_lam = _to_finite(np.sin(lam))\n    sdss_cos_lam = _to_finite(np.cos(lam))\n\n    eta_deg = _to_finite(np.degrees(eta))\n    eta_phase = _to_finite(np.mod(eta_deg, _SDSS_STRIPE_WIDTH_DEG))\n    eta_phase_centered = _to_finite(eta_phase - _SDSS_STRIPE_HALF_WIDTH_DEG)\n    stripe_phase_sin = _to_finite(np.sin(_FULL_CIRCLE_RAD * eta_phase_centered / _SDSS_STRIPE_WIDTH_DEG))\n    stripe_phase_cos = _to_finite(np.cos(_FULL_CIRCLE_RAD * eta_phase_centered / _SDSS_STRIPE_WIDTH_DEG))\n    stripe_band = np.floor(np.clip((eta_deg + 90.0) / _SDSS_STRIPE_WIDTH_DEG, -1e9, 1e9)).astype(np.int64)\n\n    return pd.DataFrame(\n        {\n            "eq_alpha_sin": eq_sin_alpha,\n            "eq_alpha_cos": eq_cos_alpha,\n            "eq_delta_sin": eq_sin_delta,\n            "eq_delta_cos": eq_cos_delta,\n            "eq_x": eq_x,\n            "eq_y": eq_y,\n            "eq_z": eq_z,\n            "gal_l": l,\n            "gal_b": b,\n            "gal_sin_l": gal_sin_l,\n            "gal_cos_l": gal_cos_l,\n            "gal_sin_b": gal_sin_b,\n            "gal_cos_b": gal_cos_b,\n            "gal_abs_b": gal_abs_b,\n            "gal_plane_complement": gal_plane_complement,\n            "gal_dist_to_gc": gal_d_gc,\n            "gal_dist_to_anticenter": gal_d_anticenter,\n            "sdss_eta": eta,\n            "sdss_lambda": lam,\n            "sdss_sin_eta": sdss_sin_eta,\n            "sdss_cos_eta": sdss_cos_eta,\n            "sdss_sin_lambda": sdss_sin_lam,\n            "sdss_cos_lambda": sdss_cos_lam,\n            "sdss_eta_phase": eta_phase,\n            "sdss_eta_phase_centered": eta_phase_centered,\n            "sdss_eta_phase_sin": stripe_phase_sin,\n            "sdss_eta_phase_cos": stripe_phase_cos,\n            "sdss_stripe_band": stripe_band,\n        },\n        index=idx,\n    )\n\n\nFEATURE_GROUPS = [\n    {\n        "name": "sky_frame_position_geometry",\n        "fn": add_sky_frame_position_geometry,\n        "depends_on": [],\n        "description": "Builds continuous spatial geometry features in equatorial, Galactic, and SDSS survey frames with discontinuity-safe angular encoding and stripe-aware periodic terms.",\n    }\n]'

HYPOTHESIS_000017_AUTOGLUON_001_PY_F265354A39_SOURCE = 'import numpy as np\nimport pandas as pd\n\n_COSMO_H0 = 70.0\n_COSMO_OMEGA_M = 0.3\n_COSMO_OMEGA_L = 0.7\n_COSMO_C_KM_S = 299792.458\n_COSMO_Z_MIN = 1e-4\n_COSMO_GRID_POINTS = 2048\n_COSMO_DL_MIN_MPC = 1.0e-4\n_COSMO_DL_MAX_MPC = 1.0e7\n_COSMO_ABS_MAG_MIN = -90.0\n_COSMO_ABS_MAG_MAX = 80.0\n_BANDS = ("u", "g", "r", "i", "z")\n_THRESHOLDS_M = (-10.0, -18.0, -23.0, -27.0)\n\n\ndef _luminosity_distance_mpc(redshift_for_distance):\n    redshift_for_distance = np.asarray(redshift_for_distance, dtype=np.float64)\n    if redshift_for_distance.size == 0:\n        return redshift_for_distance.copy()\n\n    z_max = float(np.max(redshift_for_distance))\n    if not np.isfinite(z_max):\n        z_max = float(_COSMO_Z_MIN)\n\n    # Build a fixed one-dimensional cosmology integral grid and re-use it for all rows.\n    z_grid = np.linspace(0.0, z_max, num=_COSMO_GRID_POINTS)\n    hz = np.sqrt(_COSMO_OMEGA_M * np.power(1.0 + z_grid, 3.0) + _COSMO_OMEGA_L)\n    inv_hz = 1.0 / hz\n\n    if _COSMO_GRID_POINTS > 1:\n        dz = z_grid[1] - z_grid[0]\n        seg = (inv_hz[:-1] + inv_hz[1:]) * 0.5 * dz\n        comoving = np.empty_like(z_grid)\n        comoving[0] = 0.0\n        np.cumsum(seg, out=comoving[1:])\n    else:\n        comoving = np.zeros_like(z_grid)\n\n    # Mpc = (c/H0) * (integral 0..z dz/E(z)); DL = (1+z) * D_C\n    dl = (1.0 + redshift_for_distance) * np.interp(redshift_for_distance, z_grid, comoving * (_COSMO_C_KM_S / _COSMO_H0))\n    dl = np.clip(dl, _COSMO_DL_MIN_MPC, _COSMO_DL_MAX_MPC)\n    return dl\n\n\ndef add_redshift_luminosity_plausibility(raw, deps, aux):\n    del deps, aux  # explicit dependency/aux declaration-only no-op\n    z = raw["redshift"].to_numpy(dtype=np.float64, copy=False)\n    z_eff = np.maximum(z, _COSMO_Z_MIN)\n\n    dist_mpc = _luminosity_distance_mpc(z_eff)\n    dist_mpc = np.clip(dist_mpc, _COSMO_DL_MIN_MPC, _COSMO_DL_MAX_MPC)\n    log10_dl = np.log10(dist_mpc)\n\n    abs_mag = {}\n    for band in _BANDS:\n        m_obs = raw[band].to_numpy(dtype=np.float64, copy=False)\n        m_abs = m_obs - 5.0 * log10_dl - 25.0\n        abs_mag[band] = np.clip(m_abs, _COSMO_ABS_MAG_MIN, _COSMO_ABS_MAG_MAX)\n\n    abs_matrix = np.column_stack((abs_mag["u"], abs_mag["g"], abs_mag["r"], abs_mag["i"], abs_mag["z"]))\n    abs_center_ri = 0.5 * (abs_mag["r"] + abs_mag["i"])\n    abs_brightest = np.min(abs_matrix, axis=1)\n    abs_faintest = np.max(abs_matrix, axis=1)\n    abs_spread = abs_faintest - abs_brightest\n    abs_mean = np.mean(abs_matrix, axis=1)\n\n    thresh_stellar, thresh_galaxy, thresh_qso, thresh_extreme = _THRESHOLDS_M\n\n    features = {\n        "redshift_non_positive": z <= 0.0,\n        "redshift_very_low": z < 0.01,\n        "redshift_for_distance": z_eff,\n        "luminosity_distance_mpc": dist_mpc,\n        "abs_mag_u": abs_mag["u"],\n        "abs_mag_g": abs_mag["g"],\n        "abs_mag_r": abs_mag["r"],\n        "abs_mag_i": abs_mag["i"],\n        "abs_mag_z": abs_mag["z"],\n        "abs_mag_ri_center": abs_center_ri,\n        "abs_mag_brightest_band": abs_brightest,\n        "abs_mag_faintest_band": abs_faintest,\n        "abs_mag_band_spread": abs_spread,\n        "abs_mag_band_mean": abs_mean,\n        "abs_mag_margin_to_stellar_scale": abs_center_ri - thresh_stellar,\n        "abs_mag_margin_to_galaxy_scale": abs_center_ri - thresh_galaxy,\n        "abs_mag_margin_to_quasar_scale": abs_center_ri - thresh_qso,\n        "abs_mag_margin_to_extreme_quasar_scale": abs_center_ri - thresh_extreme,\n        "abs_mag_r_margin_to_stellar_scale": abs_mag["r"] - thresh_stellar,\n        "abs_mag_r_margin_to_galaxy_scale": abs_mag["r"] - thresh_galaxy,\n        "abs_mag_r_margin_to_quasar_scale": abs_mag["r"] - thresh_qso,\n        "abs_mag_r_margin_to_extreme_quasar_scale": abs_mag["r"] - thresh_extreme,\n        "abs_band_spread_uirz": (abs_mag["u"] - abs_mag["r"]) + (abs_mag["r"] - abs_mag["i"]) + (abs_mag["i"] - abs_mag["z"]),\n    }\n\n    return pd.DataFrame(features, index=raw.index)\n\n\nFEATURE_GROUPS = [\n    {\n        "name": "redshift_luminosity_plausibility",\n        "fn": add_redshift_luminosity_plausibility,\n        "depends_on": [],\n        "description": "Convert apparent ugri z magnitudes into redshift-scaled pseudo absolute magnitudes with robust distance-distance proxies and regime-distance summaries.",\n    }\n]'

HYPOTHESIS_000021_AUTOGLUON_001_PY_B516EB8702_SOURCE = 'from __future__ import annotations\n\nimport numpy as np\nimport pandas as pd\n\n\nMAGS = ("u", "g", "r", "i", "z")\nCOLOR_PAIRS = (("u", "g"), ("g", "r"), ("r", "i"), ("i", "z"), ("u", "i"), ("u", "r"), ("g", "z"), ("r", "z"))\n\n\ndef _num(raw: pd.DataFrame, col: str) -> pd.Series:\n    if col not in raw:\n        return pd.Series(np.nan, index=raw.index, dtype="float64")\n    return pd.to_numeric(raw[col], errors="coerce").astype("float64")\n\n\ndef aide_broadband_flux_ratios(raw: pd.DataFrame, deps: dict[str, pd.DataFrame] | None = None, aux: pd.DataFrame | None = None) -> pd.DataFrame:\n    out = pd.DataFrame(index=raw.index)\n    eps = 1e-6\n\n    mags = {col: _num(raw, col) for col in MAGS}\n    for left, right in COLOR_PAIRS:\n        color = mags[left] - mags[right]\n        out[f"aide_abs_{left}_{right}"] = color.abs()\n        out[f"aide_ratio_{left}_over_{right}"] = mags[left] / (mags[right].abs() + eps)\n\n    for col, values in mags.items():\n        clipped = values.clip(-50, 50)\n        out[f"aide_log_flux_{col}"] = -0.4 * np.log(10.0) * values\n        out[f"aide_exp_flux_{col}"] = np.exp(-0.4 * np.log(10.0) * clipped)\n\n    redshift = _num(raw, "redshift")\n    clipped_z = redshift.clip(lower=0)\n    out["aide_redshift_clipped"] = clipped_z\n    out["aide_redshift_log1p"] = np.log1p(clipped_z)\n    out["aide_redshift_sq"] = clipped_z ** 2\n    out["aide_redshift_cube"] = clipped_z ** 3\n    out["aide_u_r_i_curv"] = mags["u"] - 2.0 * mags["r"] + mags["i"]\n    out["aide_g_i_z_curv"] = mags["g"] - 2.0 * mags["i"] + mags["z"]\n    return out.replace([np.inf, -np.inf], np.nan)\n\n\nFEATURE_GROUPS = [\n    {\n        "name": "aide_broadband_flux_ratios",\n        "fn": aide_broadband_flux_ratios,\n        "depends_on": [],\n        "description": "AIDE top-5 broadband ratios, absolute colors, pseudo-flux values, and redshift powers.",\n    }\n]\n'

HYPOTHESIS_000022_AUTOGLUON_001_PY_613518C2A7_SOURCE = 'from __future__ import annotations\n\nimport numpy as np\nimport pandas as pd\n\n\nMAGS = ("u", "g", "r", "i", "z")\n\n\ndef _num(raw: pd.DataFrame, col: str) -> pd.Series:\n    if col not in raw:\n        return pd.Series(np.nan, index=raw.index, dtype="float64")\n    return pd.to_numeric(raw[col], errors="coerce").astype("float64")\n\n\ndef _sky_key(raw: pd.DataFrame) -> pd.Series:\n    alpha = _num(raw, "alpha").fillna(0.0)\n    delta = _num(raw, "delta").fillna(0.0)\n    a_bin = np.floor(alpha * 2.0).astype("int64")\n    d_bin = np.floor((delta + 90.0) * 2.0).astype("int64")\n    return pd.Series(a_bin.astype(str) + "_" + d_bin.astype(str), index=raw.index)\n\n\ndef _colors(raw: pd.DataFrame) -> pd.DataFrame:\n    u, g, r, i, z = (_num(raw, col) for col in MAGS)\n    return pd.DataFrame(\n        {\n            "u_g": u - g,\n            "g_r": g - r,\n            "r_i": r - i,\n            "i_z": i - z,\n            "u_i": u - i,\n            "u_r": u - r,\n            "g_z": g - z,\n            "r_z": r - z,\n            "u_r_i_curv": u - 2.0 * r + i,\n            "g_i_z_curv": g - 2.0 * i + z,\n        },\n        index=raw.index,\n    )\n\n\ndef aide_sky_cell_local_residuals(raw: pd.DataFrame, deps: dict[str, pd.DataFrame] | None = None, aux: pd.DataFrame | None = None) -> pd.DataFrame:\n    out = pd.DataFrame(index=raw.index)\n    key = _sky_key(raw)\n    counts = key.map(key.value_counts()).astype("float64")\n    out["aide_sky_cell_count"] = counts\n\n    parts = key.str.split("_", expand=True).astype("int64")\n    a_bin = parts[0]\n    d_bin = parts[1]\n    count_map = key.value_counts().to_dict()\n    neighbor_counts = []\n    for a_val, d_val in zip(a_bin.to_numpy(), d_bin.to_numpy()):\n        total = 0\n        for da in (-1, 0, 1):\n            for dd in (-1, 0, 1):\n                total += count_map.get(f"{a_val + da}_{d_val + dd}", 0)\n        neighbor_counts.append(total)\n    out["aide_sky_cell_3x3_count"] = np.asarray(neighbor_counts, dtype="float64")\n    out["aide_sky_concentration"] = out["aide_sky_cell_count"] / (out["aide_sky_cell_3x3_count"] + 1.0)\n\n    values = pd.DataFrame({col: _num(raw, col) for col in MAGS}, index=raw.index)\n    values["redshift_clipped"] = _num(raw, "redshift").clip(lower=0)\n    residual_l2 = pd.Series(0.0, index=raw.index)\n    residual_l1 = pd.Series(0.0, index=raw.index)\n    z_max = pd.Series(0.0, index=raw.index)\n\n    for col in values.columns:\n        mean = values[col].groupby(key).transform("mean")\n        std = values[col].groupby(key).transform("std").replace(0, np.nan)\n        delta = values[col] - mean\n        z_score = delta / std\n        out[f"aide_{col}_sky_cell_delta"] = delta\n        out[f"aide_{col}_sky_cell_z"] = z_score\n        residual_l2 = residual_l2 + delta.fillna(0.0) ** 2\n        residual_l1 = residual_l1 + delta.abs().fillna(0.0)\n        z_max = np.maximum(z_max, z_score.abs().fillna(0.0))\n\n    out["aide_sky_cell_residual_l2"] = np.sqrt(residual_l2)\n    out["aide_sky_cell_residual_abs_l1"] = residual_l1\n    out["aide_sky_cell_z_max"] = z_max\n\n    color_values = _colors(raw)\n    color_l2 = pd.Series(0.0, index=raw.index)\n    color_l1 = pd.Series(0.0, index=raw.index)\n    color_z_max = pd.Series(0.0, index=raw.index)\n    color_deltas = []\n    for col in color_values.columns:\n        mean = color_values[col].groupby(key).transform("mean")\n        std = color_values[col].groupby(key).transform("std").replace(0, np.nan)\n        delta = color_values[col] - mean\n        z_score = delta / std\n        out[f"aide_{col}_sky_color_cell_delta"] = delta\n        out[f"aide_{col}_sky_color_cell_z"] = z_score\n        color_l2 = color_l2 + delta.fillna(0.0) ** 2\n        color_l1 = color_l1 + delta.abs().fillna(0.0)\n        color_z_max = np.maximum(color_z_max, z_score.abs().fillna(0.0))\n        color_deltas.append(delta)\n\n    delta_frame = pd.concat(color_deltas, axis=1)\n    out["aide_sky_color_cell_residual_l2"] = np.sqrt(color_l2)\n    out["aide_sky_color_cell_residual_abs_l1"] = color_l1\n    out["aide_sky_color_cell_delta_mean"] = delta_frame.mean(axis=1)\n    out["aide_sky_color_cell_delta_std"] = delta_frame.std(axis=1)\n    out["aide_sky_color_cell_z_max"] = color_z_max\n    return out.replace([np.inf, -np.inf], np.nan)\n\n\nFEATURE_GROUPS = [\n    {\n        "name": "aide_sky_cell_local_residuals",\n        "fn": aide_sky_cell_local_residuals,\n        "depends_on": [],\n        "description": "AIDE half-degree sky-cell densities and local residual/z-score features.",\n    }\n]\n'

HYPOTHESIS_000023_AUTOGLUON_001_PY_36182E7404_SOURCE = 'from __future__ import annotations\n\nimport numpy as np\nimport pandas as pd\n\n\nMAGS = ("u", "g", "r", "i", "z")\n\n\ndef _num(raw: pd.DataFrame, col: str) -> pd.Series:\n    if col not in raw:\n        return pd.Series(np.nan, index=raw.index, dtype="float64")\n    return pd.to_numeric(raw[col], errors="coerce").astype("float64")\n\n\ndef _colors(raw: pd.DataFrame) -> pd.DataFrame:\n    u, g, r, i, z = (_num(raw, col) for col in MAGS)\n    return pd.DataFrame(\n        {\n            "u_g": u - g,\n            "g_r": g - r,\n            "r_i": r - i,\n            "i_z": i - z,\n            "u_i": u - i,\n            "u_r": u - r,\n            "g_z": g - z,\n            "r_z": r - z,\n            "u_r_i_curv": u - 2.0 * r + i,\n            "g_i_z_curv": g - 2.0 * i + z,\n        },\n        index=raw.index,\n    )\n\n\ndef aide_redshift_bin_color_residuals(raw: pd.DataFrame, deps: dict[str, pd.DataFrame] | None = None, aux: pd.DataFrame | None = None) -> pd.DataFrame:\n    out = pd.DataFrame(index=raw.index)\n    redshift = _num(raw, "redshift").clip(lower=0)\n    bins = pd.qcut(redshift.rank(method="first"), q=24, duplicates="drop", labels=False)\n    bins = pd.Series(bins, index=raw.index)\n    colors = _colors(raw)\n\n    residual_l2 = pd.Series(0.0, index=raw.index)\n    residual_l1 = pd.Series(0.0, index=raw.index)\n    z_max = pd.Series(0.0, index=raw.index)\n    deltas = []\n    for col in colors.columns:\n        mean = colors[col].groupby(bins).transform("mean")\n        std = colors[col].groupby(bins).transform("std").replace(0, np.nan)\n        delta = colors[col] - mean\n        z_score = delta / std\n        out[f"aide_{col}_redshift_bin_delta"] = delta\n        out[f"aide_{col}_redshift_bin_z"] = z_score\n        residual_l2 = residual_l2 + delta.fillna(0.0) ** 2\n        residual_l1 = residual_l1 + delta.abs().fillna(0.0)\n        z_max = np.maximum(z_max, z_score.abs().fillna(0.0))\n        deltas.append(delta)\n\n    delta_frame = pd.concat(deltas, axis=1)\n    out["aide_redshift_color_residual_l2"] = np.sqrt(residual_l2)\n    out["aide_redshift_color_residual_abs_l1"] = residual_l1\n    out["aide_redshift_color_delta_mean"] = delta_frame.mean(axis=1)\n    out["aide_redshift_color_delta_std"] = delta_frame.std(axis=1)\n    out["aide_redshift_color_z_max"] = z_max\n    return out.replace([np.inf, -np.inf], np.nan)\n\n\nFEATURE_GROUPS = [\n    {\n        "name": "aide_redshift_bin_color_residuals",\n        "fn": aide_redshift_bin_color_residuals,\n        "depends_on": [],\n        "description": "AIDE qcut-redshift color residuals and aggregate residual scores.",\n    }\n]\n'

HYPOTHESIS_000024_AUTOGLUON_001_PY_BAA2CCA7DA_SOURCE = 'from __future__ import annotations\n\nimport numpy as np\nimport pandas as pd\n\n\nNUMERIC_COLS = ("u", "g", "r", "i", "z", "redshift")\nCAT_COLS = ("spectral_type", "galaxy_population")\n\n\ndef _num(raw: pd.DataFrame, col: str) -> pd.Series:\n    if col not in raw:\n        return pd.Series(np.nan, index=raw.index, dtype="float64")\n    return pd.to_numeric(raw[col], errors="coerce").astype("float64")\n\n\ndef _cat(raw: pd.DataFrame, col: str) -> pd.Series:\n    if col not in raw:\n        return pd.Series("__missing__", index=raw.index, dtype="object")\n    return raw[col].astype("string").fillna("__missing__").astype("object")\n\n\ndef _qbin(values: pd.Series, q: int = 12) -> pd.Series:\n    ranked = values.rank(method="first")\n    try:\n        return pd.qcut(ranked, q=q, labels=False, duplicates="drop")\n    except ValueError:\n        return pd.Series(0, index=values.index, dtype="float64")\n\n\ndef aide_catalog_rank_frequency_context(raw: pd.DataFrame, deps: dict[str, pd.DataFrame] | None = None, aux: pd.DataFrame | None = None) -> pd.DataFrame:\n    out = pd.DataFrame(index=raw.index)\n    cats = {col: _cat(raw, col) for col in CAT_COLS}\n\n    for col, values in cats.items():\n        freq = values.map(values.value_counts(normalize=True)).astype("float64")\n        out[f"aide_{col}_freq"] = freq\n\n    cross = cats["spectral_type"].astype(str) + "__" + cats["galaxy_population"].astype(str)\n    out["aide_spectral_type_x_pop_freq"] = cross.map(cross.value_counts(normalize=True)).astype("float64")\n\n    rank_cols = {col: _num(raw, col) for col in NUMERIC_COLS}\n    rank_cols["redshift_log1p"] = np.log1p(rank_cols["redshift"].clip(lower=0))\n    rank_values = []\n    for col, values in rank_cols.items():\n        rank = values.rank(pct=True)\n        qbin = pd.Series(_qbin(values), index=raw.index)\n        out[f"aide_{col}_rank_pct"] = rank\n        out[f"aide_{col}_qbin"] = qbin.astype("float64")\n        out[f"aide_{col}_qbin_freq"] = qbin.map(qbin.value_counts(normalize=True)).astype("float64")\n        rank_values.append(rank)\n\n        for cat_col, cat_values in cats.items():\n            grouped_rank = values.groupby(cat_values).rank(pct=True)\n            out[f"aide_{col}_rank_within_{cat_col}"] = grouped_rank\n\n    rank_frame = pd.concat(rank_values, axis=1)\n    out["aide_numeric_rank_mean"] = rank_frame.mean(axis=1)\n    out["aide_numeric_rank_std"] = rank_frame.std(axis=1)\n    return out.replace([np.inf, -np.inf], np.nan)\n\n\nFEATURE_GROUPS = [\n    {\n        "name": "aide_catalog_rank_frequency_context",\n        "fn": aide_catalog_rank_frequency_context,\n        "depends_on": [],\n        "description": "AIDE category frequency, cross-frequency, global rank, qbin, and within-category rank context.",\n    }\n]\n'

HYPOTHESIS_000025_AUTOGLUON_001_PY_658E2F200F_SOURCE = 'from __future__ import annotations\n\nimport numpy as np\nimport pandas as pd\n\n\nAUX_COLS = ("alpha", "delta", "u", "g", "r", "i", "z", "redshift")\n\n\ndef _num(frame: pd.DataFrame, col: str, index: pd.Index | None = None) -> pd.Series:\n    if col not in frame:\n        idx = frame.index if index is None else index\n        return pd.Series(np.nan, index=idx, dtype="float64")\n    return pd.to_numeric(frame[col], errors="coerce").astype("float64")\n\n\ndef _clean_aux(aux: pd.DataFrame | None) -> pd.DataFrame:\n    if aux is None or aux.empty:\n        return pd.DataFrame(columns=AUX_COLS)\n    cleaned = pd.DataFrame(index=aux.index)\n    for col in AUX_COLS:\n        values = _num(aux, col)\n        if col in {"u", "g", "r", "i", "z"}:\n            values = values.mask(values <= -9000)\n        if col == "redshift":\n            values = values.clip(lower=0)\n        cleaned[col] = values\n    return cleaned.dropna(how="all")\n\n\ndef aide_aux_reference_distribution_distance(raw: pd.DataFrame, deps: dict[str, pd.DataFrame] | None = None, aux: pd.DataFrame | None = None) -> pd.DataFrame:\n    out = pd.DataFrame(index=raw.index)\n    aux_ref = _clean_aux(aux)\n    raw_values = pd.DataFrame(index=raw.index)\n    for col in AUX_COLS:\n        values = _num(raw, col)\n        if col == "redshift":\n            values = values.clip(lower=0)\n        raw_values[col] = values\n\n    if aux_ref.empty:\n        for col in AUX_COLS:\n            out[f"aide_aux_{col}_z"] = 0.0\n            out[f"aide_aux_{col}_med_delta_abs"] = 0.0\n            out[f"aide_aux_{col}_cdf"] = 0.5\n        out["aide_aux_joint_l2"] = 0.0\n        out["aide_aux_ref_mahalanobis2"] = 0.0\n        out["aide_aux_ref_mahalanobis"] = 0.0\n        out["aide_aux_ref_mahalanobis_inlier"] = 1.0\n        return out\n\n    joint = pd.Series(0.0, index=raw.index)\n    for col in AUX_COLS:\n        ref = aux_ref[col].dropna()\n        if ref.empty:\n            out[f"aide_aux_{col}_z"] = 0.0\n            out[f"aide_aux_{col}_med_delta_abs"] = 0.0\n            out[f"aide_aux_{col}_cdf"] = 0.5\n            continue\n        median = ref.median()\n        mad = (ref - median).abs().median()\n        scale = 1.4826 * mad if mad and np.isfinite(mad) else ref.std(ddof=0)\n        if not scale or not np.isfinite(scale):\n            scale = 1.0\n        z_score = (raw_values[col] - median) / scale\n        out[f"aide_aux_{col}_z"] = z_score\n        out[f"aide_aux_{col}_med_delta_abs"] = (raw_values[col] - median).abs()\n        ranks = np.searchsorted(np.sort(ref.to_numpy()), raw_values[col].to_numpy(), side="right") / max(len(ref), 1)\n        out[f"aide_aux_{col}_cdf"] = ranks\n        joint = joint + z_score.fillna(0.0) ** 2\n\n    out["aide_aux_joint_l2"] = np.sqrt(joint)\n\n    matrix = aux_ref[list(AUX_COLS)].dropna()\n    if len(matrix) <= len(AUX_COLS):\n        out["aide_aux_ref_mahalanobis2"] = out["aide_aux_joint_l2"] ** 2\n    else:\n        center = matrix.median(axis=0)\n        spread = (matrix - center).abs().median(axis=0).replace(0, np.nan)\n        standardized_ref = ((matrix - center) / spread.fillna(1.0)).fillna(0.0)\n        standardized_raw = ((raw_values[list(AUX_COLS)] - center) / spread.fillna(1.0)).fillna(0.0)\n        cov = np.cov(standardized_ref.to_numpy(), rowvar=False)\n        inv_cov = np.linalg.pinv(cov)\n        vals = standardized_raw.to_numpy()\n        out["aide_aux_ref_mahalanobis2"] = np.einsum("ij,jk,ik->i", vals, inv_cov, vals)\n\n    out["aide_aux_ref_mahalanobis"] = np.sqrt(out["aide_aux_ref_mahalanobis2"].clip(lower=0))\n    threshold = np.nanpercentile(out["aide_aux_ref_mahalanobis"], 95)\n    out["aide_aux_ref_mahalanobis_inlier"] = (out["aide_aux_ref_mahalanobis"] <= threshold).astype("float64")\n    return out.replace([np.inf, -np.inf], np.nan)\n\n\nFEATURE_GROUPS = [\n    {\n        "name": "aide_aux_reference_distribution_distance",\n        "fn": aide_aux_reference_distribution_distance,\n        "depends_on": [],\n        "description": "AIDE robust auxiliary-reference z, CDF, joint distance, and Mahalanobis features.",\n    }\n]\n'

HYPOTHESIS_000026_AUTOGLUON_004_PY_55FDD09202_SOURCE = 'import numpy as np\nimport pandas as pd\n\n_GROUP_NAME = "aide_smooth_spline_sed_interactions"\n_ALPHA_KNOTS = 7\n_OTHER_KNOTS = 5\n_BSPLINE_DEGREE = 3\n_INTERACTION_BASIS = 2\n\n\ndef _coerce_series(values):\n    return pd.to_numeric(values, errors="coerce")\n\n\ndef _bounds_from_series(main_series, auxiliary_series=None):\n    combined = main_series if auxiliary_series is None else pd.concat([main_series, auxiliary_series], ignore_index=True)\n    arr = combined.to_numpy(dtype=float)\n    finite = np.isfinite(arr)\n    if not np.any(finite):\n        arr = main_series.to_numpy(dtype=float)\n        finite = np.isfinite(arr)\n    if not np.any(finite):\n        return 0.0, 1.0\n    lo = float(np.nanmin(arr[finite]))\n    hi = float(np.nanmax(arr[finite]))\n    if not np.isfinite(lo) or not np.isfinite(hi) or hi <= lo:\n        return 0.0, 1.0\n    return lo, hi\n\n\ndef _difference_series(raw_df, aux_df, left_col, right_col):\n    left = _coerce_series(raw_df[left_col])\n    right = _coerce_series(raw_df[right_col])\n    raw_series = left - right\n    aux_series = None\n    if isinstance(aux_df, pd.DataFrame) and not aux_df.empty and left_col in aux_df.columns and right_col in aux_df.columns:\n        left_aux = _coerce_series(aux_df[left_col])\n        right_aux = _coerce_series(aux_df[right_col])\n        aux_series = left_aux - right_aux\n    return raw_series, aux_series\n\n\ndef _manual_bspline_basis(values, lower, upper, n_internal_knots, degree=_BSPLINE_DEGREE):\n    x = np.asarray(values, dtype=float)\n    n = len(x)\n    if not np.isfinite(lower) or not np.isfinite(upper) or upper <= lower or n == 0:\n        out = np.full((n, 1), np.nan, dtype=np.float32)\n        finite = np.isfinite(x)\n        out[finite, 0] = 1.0\n        return out\n\n    n_internal = max(2, int(n_internal_knots))\n    internal = np.linspace(lower, upper, n_internal + 2)[1:-1]\n    knots = np.r_[np.repeat(lower, degree + 1), internal, np.repeat(upper, degree + 1)]\n    n_basis = len(knots) - degree - 1\n    out = np.full((n, n_basis), np.nan, dtype=np.float32)\n\n    finite = np.isfinite(x)\n    if not np.any(finite):\n        return out\n\n    xv = x.copy()\n    xv[~finite] = lower\n    xv = np.clip(xv, lower, upper)\n    xi = xv[finite]\n    m = len(knots)\n    N = np.zeros((len(xi), m - 1), dtype=np.float64)\n\n    left = xi[:, None] >= knots[:-1][None, :]\n    right = xi[:, None] < knots[1:][None, :]\n    N[:, : m - 1] = (left & right).astype(np.float64)\n    N[xi == upper, n_basis - 1] = 1.0\n\n    for d in range(1, degree + 1):\n        n_cols = m - d - 1\n        N_next = np.zeros((len(xi), n_cols), dtype=np.float64)\n        for i in range(n_cols):\n            d1 = knots[i + d] - knots[i]\n            d2 = knots[i + d + 1] - knots[i + 1]\n            left_term = 0.0\n            right_term = 0.0\n            if d1 != 0.0:\n                left_term = ((xi - knots[i]) / d1) * N[:, i]\n            if d2 != 0.0:\n                right_term = ((knots[i + d + 1] - xi) / d2) * N[:, i + 1]\n            N_next[:, i] = left_term + right_term\n        N = N_next\n\n    finite_idx = np.flatnonzero(finite)\n    out[finite_idx] = N.astype(np.float32)\n    return out\n\n\ndef _nonperiodic_cubic_basis(values, lower, upper, n_knots):\n    arr = _coerce_series(values).to_numpy(dtype=float)\n    n = len(arr)\n    n_knots = int(max(2, n_knots))\n    if n == 0:\n        return np.empty((0, 0), dtype=np.float32)\n    if not np.isfinite(lower) or not np.isfinite(upper) or upper <= lower:\n        out = np.full((n, 1), np.nan, dtype=np.float32)\n        finite = np.isfinite(arr)\n        out[finite, 0] = 1.0\n        return out\n\n    internal = np.linspace(lower, upper, n_knots + 2)[1:-1]\n    knots = np.r_[np.repeat(lower, _BSPLINE_DEGREE + 1), internal, np.repeat(upper, _BSPLINE_DEGREE + 1)]\n    n_basis = len(knots) - _BSPLINE_DEGREE - 1\n    out = np.full((n, n_basis), np.nan, dtype=np.float32)\n\n    finite = np.isfinite(arr)\n    if not np.any(finite):\n        return out\n\n    x = np.clip(arr[finite], lower, upper)\n    try:\n        from scipy.interpolate import BSpline\n\n        coeff = np.eye(n_basis)\n        spline = BSpline(knots, coeff, _BSPLINE_DEGREE, axis=0, extrapolate=False)\n        basis = spline(x).astype(np.float64)\n    except Exception:\n        basis = _manual_bspline_basis(arr[finite], lower, upper, n_knots, degree=_BSPLINE_DEGREE)\n\n    if basis.ndim == 1:\n        basis = basis[:, None]\n    finite_idx = np.flatnonzero(finite)\n    out[finite_idx] = basis.astype(np.float32)\n    return out\n\n\ndef _periodic_cubic_basis(values, lower, upper, n_knots):\n    arr = _coerce_series(values).to_numpy(dtype=float)\n    n = len(arr)\n    n_knots = int(max(3, n_knots))\n    if n == 0:\n        return np.empty((0, 0), dtype=np.float32)\n    if not np.isfinite(lower) or not np.isfinite(upper) or upper <= lower:\n        out = np.full((n, 1), np.nan, dtype=np.float32)\n        finite = np.isfinite(arr)\n        out[finite, 0] = 1.0\n        return out\n\n    out = np.full((n, n_knots), np.nan, dtype=np.float32)\n    finite = np.isfinite(arr)\n    if not np.any(finite):\n        return out\n\n    period = upper - lower\n    if not np.isfinite(period) or period <= 0.0:\n        fallback = _manual_bspline_basis(arr[finite], lower, upper, n_knots, degree=_BSPLINE_DEGREE)\n        fallback = np.asarray(fallback, dtype=np.float32)\n        if fallback.shape[1] >= n_knots:\n            fallback = fallback[:, :n_knots]\n        else:\n            pad = np.full((fallback.shape[0], n_knots - fallback.shape[1]), np.nan, dtype=np.float32)\n            fallback = np.concatenate([fallback, pad], axis=1)\n        out[np.flatnonzero(finite)] = fallback\n        return out\n\n    xw = ((arr[finite] - lower) % period) + lower\n    try:\n        from scipy.interpolate import CubicSpline\n\n        nodes = np.linspace(lower, upper, n_knots + 1)\n        y = np.zeros((len(nodes), n_knots), dtype=float)\n        for i in range(n_knots):\n            y[i, i] = 1.0\n            if i == 0:\n                y[-1, i] = 1.0\n        spline = CubicSpline(nodes, y, bc_type="periodic", axis=0)\n        basis = spline(xw).astype(np.float32)\n    except Exception:\n        basis = _manual_bspline_basis(xw, lower, upper, n_knots, degree=_BSPLINE_DEGREE)\n        basis = np.asarray(basis, dtype=np.float32)\n        if basis.shape[1] >= n_knots:\n            basis = basis[:, :n_knots]\n        else:\n            pad = np.full((basis.shape[0], n_knots - basis.shape[1]), np.nan, dtype=np.float32)\n            basis = np.concatenate([basis, pad], axis=1)\n\n    out[np.flatnonzero(finite)] = basis\n    return out\n\n\ndef _add_basis_columns(store, basis_matrix, prefix):\n    for i in range(basis_matrix.shape[1]):\n        store[f"{prefix}_spline_b{i + 1:02d}"] = basis_matrix[:, i]\n\n\ndef _add_interaction_columns(store, left_matrix, right_matrix, name, max_terms=_INTERACTION_BASIS):\n    if left_matrix.size == 0 or right_matrix.size == 0:\n        return\n    left_terms = left_matrix[:, : min(max_terms, left_matrix.shape[1])]\n    right_terms = right_matrix[:, : min(max_terms, right_matrix.shape[1])]\n    for i in range(left_terms.shape[1]):\n        for j in range(right_terms.shape[1]):\n            store[f"{name}_b{i + 1:02d}_x{j + 1:02d}"] = left_terms[:, i] * right_terms[:, j]\n\n\ndef add_aide_smooth_spline_sed_interactions(raw, deps, aux):\n    _ = deps\n    aux_df = aux if isinstance(aux, pd.DataFrame) else pd.DataFrame()\n\n    alpha = _coerce_series(raw["alpha"])\n    delta = _coerce_series(raw["delta"])\n    u = _coerce_series(raw["u"])\n    g = _coerce_series(raw["g"])\n    r = _coerce_series(raw["r"])\n    i_band = _coerce_series(raw["i"])\n    z_band = _coerce_series(raw["z"])\n    redshift = _coerce_series(raw["redshift"])\n\n    alpha_aux = _coerce_series(aux_df["alpha"]) if not aux_df.empty and "alpha" in aux_df.columns else None\n    delta_aux = _coerce_series(aux_df["delta"]) if not aux_df.empty and "delta" in aux_df.columns else None\n    u_aux = _coerce_series(aux_df["u"]) if not aux_df.empty and "u" in aux_df.columns else None\n    g_aux = _coerce_series(aux_df["g"]) if not aux_df.empty and "g" in aux_df.columns else None\n    r_aux = _coerce_series(aux_df["r"]) if not aux_df.empty and "r" in aux_df.columns else None\n    i_aux = _coerce_series(aux_df["i"]) if not aux_df.empty and "i" in aux_df.columns else None\n    z_aux = _coerce_series(aux_df["z"]) if not aux_df.empty and "z" in aux_df.columns else None\n    redshift_aux = _coerce_series(aux_df["redshift"]) if not aux_df.empty and "redshift" in aux_df.columns else None\n\n    u_g, u_g_aux = _difference_series(raw, aux_df, "u", "g")\n    g_r, g_r_aux = _difference_series(raw, aux_df, "g", "r")\n    r_i, r_i_aux = _difference_series(raw, aux_df, "r", "i")\n    i_z, i_z_aux = _difference_series(raw, aux_df, "i", "z")\n    u_r, u_r_aux = _difference_series(raw, aux_df, "u", "r")\n    g_i, g_i_aux = _difference_series(raw, aux_df, "g", "i")\n    r_z, r_z_aux = _difference_series(raw, aux_df, "r", "z")\n    u_z, u_z_aux = _difference_series(raw, aux_df, "u", "z")\n\n    redshift_hi = _bounds_from_series(redshift, redshift_aux)[1]\n    if not np.isfinite(redshift_hi):\n        redshift_hi = float(redshift.max(skipna=True))\n    if not np.isfinite(redshift_hi):\n        redshift_hi = 0.0\n    clipped_redshift = redshift.clip(lower=0.0, upper=redshift_hi)\n    clipped_redshift_aux = redshift_aux.clip(lower=0.0, upper=redshift_hi) if redshift_aux is not None else None\n\n    feature_blocks = {}\n\n    alpha_bounds = _bounds_from_series(alpha, alpha_aux)\n    feature_blocks["alpha"] = _periodic_cubic_basis(alpha, alpha_bounds[0], alpha_bounds[1], _ALPHA_KNOTS)\n\n    delta_bounds = _bounds_from_series(delta, delta_aux)\n    feature_blocks["delta"] = _nonperiodic_cubic_basis(delta, delta_bounds[0], delta_bounds[1], _OTHER_KNOTS)\n\n    u_bounds = _bounds_from_series(u, u_aux)\n    feature_blocks["u"] = _nonperiodic_cubic_basis(u, u_bounds[0], u_bounds[1], _OTHER_KNOTS)\n\n    g_bounds = _bounds_from_series(g, g_aux)\n    feature_blocks["g"] = _nonperiodic_cubic_basis(g, g_bounds[0], g_bounds[1], _OTHER_KNOTS)\n\n    r_bounds = _bounds_from_series(r, r_aux)\n    feature_blocks["r"] = _nonperiodic_cubic_basis(r, r_bounds[0], r_bounds[1], _OTHER_KNOTS)\n\n    i_bounds = _bounds_from_series(i_band, i_aux)\n    feature_blocks["i"] = _nonperiodic_cubic_basis(i_band, i_bounds[0], i_bounds[1], _OTHER_KNOTS)\n\n    z_bounds = _bounds_from_series(z_band, z_aux)\n    feature_blocks["z"] = _nonperiodic_cubic_basis(z_band, z_bounds[0], z_bounds[1], _OTHER_KNOTS)\n\n    clipped_z_bounds = _bounds_from_series(clipped_redshift, clipped_redshift_aux)\n    feature_blocks["clipped_redshift"] = _nonperiodic_cubic_basis(\n        clipped_redshift, clipped_z_bounds[0], clipped_z_bounds[1], _OTHER_KNOTS\n    )\n\n    u_g_bounds = _bounds_from_series(u_g, u_g_aux)\n    feature_blocks["u_g"] = _nonperiodic_cubic_basis(u_g, u_g_bounds[0], u_g_bounds[1], _OTHER_KNOTS)\n\n    g_r_bounds = _bounds_from_series(g_r, g_r_aux)\n    feature_blocks["g_r"] = _nonperiodic_cubic_basis(g_r, g_r_bounds[0], g_r_bounds[1], _OTHER_KNOTS)\n\n    r_i_bounds = _bounds_from_series(r_i, r_i_aux)\n    feature_blocks["r_i"] = _nonperiodic_cubic_basis(r_i, r_i_bounds[0], r_i_bounds[1], _OTHER_KNOTS)\n\n    i_z_bounds = _bounds_from_series(i_z, i_z_aux)\n    feature_blocks["i_z"] = _nonperiodic_cubic_basis(i_z, i_z_bounds[0], i_z_bounds[1], _OTHER_KNOTS)\n\n    u_r_bounds = _bounds_from_series(u_r, u_r_aux)\n    feature_blocks["u_r"] = _nonperiodic_cubic_basis(u_r, u_r_bounds[0], u_r_bounds[1], _OTHER_KNOTS)\n\n    g_i_bounds = _bounds_from_series(g_i, g_i_aux)\n    feature_blocks["g_i"] = _nonperiodic_cubic_basis(g_i, g_i_bounds[0], g_i_bounds[1], _OTHER_KNOTS)\n\n    r_z_bounds = _bounds_from_series(r_z, r_z_aux)\n    feature_blocks["r_z"] = _nonperiodic_cubic_basis(r_z, r_z_bounds[0], r_z_bounds[1], _OTHER_KNOTS)\n\n    u_z_bounds = _bounds_from_series(u_z, u_z_aux)\n    feature_blocks["u_z"] = _nonperiodic_cubic_basis(u_z, u_z_bounds[0], u_z_bounds[1], _OTHER_KNOTS)\n\n    out = {}\n    for name, matrix in feature_blocks.items():\n        _add_basis_columns(out, matrix, name)\n\n    _add_interaction_columns(out, feature_blocks["clipped_redshift"], feature_blocks["u_g"], "redshift_x_u_g")\n    _add_interaction_columns(out, feature_blocks["clipped_redshift"], feature_blocks["g_r"], "redshift_x_g_r")\n    _add_interaction_columns(out, feature_blocks["clipped_redshift"], feature_blocks["r_i"], "redshift_x_r_i")\n    _add_interaction_columns(out, feature_blocks["g_r"], feature_blocks["r_i"], "g_r_x_r_i")\n\n    return pd.DataFrame(out, index=raw.index)\n\n\nFEATURE_GROUPS = [\n    {\n        "name": _GROUP_NAME,\n        "fn": add_aide_smooth_spline_sed_interactions,\n        "depends_on": [],\n        "description": "Add cubic spline expansions for sky coordinates, photometry, clipped redshift, and color indices with compact interactions over redshift-color and adjacent color terms.",\n    }\n]'

HYPOTHESIS_000027_AUTOGLUON_001_PY_B2F52F7A5E_SOURCE = 'from __future__ import annotations\n\nimport numpy as np\nimport pandas as pd\n\n\ndef _id_values(raw: pd.DataFrame) -> pd.Series:\n    if "id" not in raw:\n        return pd.Series(np.arange(len(raw), dtype="float64"), index=raw.index)\n    return pd.to_numeric(raw["id"], errors="coerce").astype("float64")\n\n\ndef aide_id_sequence_scan_context(raw: pd.DataFrame, deps: dict[str, pd.DataFrame] | None = None, aux: pd.DataFrame | None = None) -> pd.DataFrame:\n    out = pd.DataFrame(index=raw.index)\n    ids = _id_values(raw)\n    fallback = pd.Series(np.arange(len(raw), dtype="float64"), index=raw.index)\n    filled = ids.fillna(fallback)\n\n    rank = filled.rank(method="first")\n    denom = max(len(raw) - 1, 1)\n    out["aide_id_is_missing"] = ids.isna().astype("float64")\n    out["aide_id_rank"] = rank\n    out["aide_id_rank_norm"] = (rank - 1.0) / denom\n    out["aide_id_block_1k"] = np.floor(filled / 1_000.0)\n    out["aide_id_block_100k"] = np.floor(filled / 100_000.0)\n    out["aide_id_mod_2"] = np.mod(filled, 2.0)\n    out["aide_id_mod_11"] = np.mod(filled, 11.0)\n    out["aide_id_mod_97"] = np.mod(filled, 97.0)\n    out["aide_id_even"] = (np.mod(filled, 2.0) == 0).astype("float64")\n    out["aide_id_log1p"] = np.log1p(filled.clip(lower=0))\n\n    ordered = pd.DataFrame({"id": filled, "position": np.arange(len(raw))}, index=raw.index).sort_values("id", kind="mergesort")\n    prev_gap = ordered["id"].diff()\n    next_gap = ordered["id"].shift(-1) - ordered["id"]\n    ordered["aide_id_gap_prev"] = prev_gap\n    ordered["aide_id_gap_next"] = next_gap\n    restored = ordered.sort_values("position", kind="mergesort")\n    out["aide_id_gap_prev"] = restored["aide_id_gap_prev"].to_numpy()\n    out["aide_id_gap_next"] = restored["aide_id_gap_next"].to_numpy()\n    return out.replace([np.inf, -np.inf], np.nan)\n\n\nFEATURE_GROUPS = [\n    {\n        "name": "aide_id_sequence_scan_context",\n        "fn": aide_id_sequence_scan_context,\n        "depends_on": [],\n        "description": "AIDE id rank, block, modulo, parity, log, and neighbor-gap sequence features.",\n    }\n]\n'

HYPOTHESIS_000028_AUTOGLUON_005_PY_2AEF17B032_SOURCE = 'import numpy as np\nimport pandas as pd\n\nSFD98_SCALE = 0.86\nEXTINCTION_COEFFS = (5.155, 3.793, 2.751, 2.086, 1.479)\nEQ_TO_GAL_MATRIX = (\n    (-0.0548755604, -0.8734370902, -0.4838350155),\n    (0.4941094279, -0.4448296300, 0.7469822445),\n    (-0.8676661490, -0.1980763734, 0.4559837762),\n)\nBIN_SIZE_DEG = 5.0\nEBV_MIN = 0.0\nEBV_MAX = 1.2\nCLIP_Q_LOW = 0.005\nCLIP_Q_HIGH = 0.995\nLAT_BIN_COUNT = 10\nNEAREST_BIN_MAX_DEG = 10.0\n\ndef _to_series(values, index):\n    return pd.Series(pd.to_numeric(values, errors="coerce"), index=index, dtype="float64")\n\ndef _normalize_name(name):\n    return "".join(ch for ch in str(name).lower() if ch.isalnum())\n\ndef _find_column(columns, candidates):\n    norm = {_normalize_name(c): c for c in columns}\n    for cand in candidates:\n        if cand in norm:\n            return norm[cand]\n    for cand in candidates:\n        if len(cand) <= 1:\n            continue\n        for key, col in norm.items():\n            if cand in key:\n                return col\n    return None\n\ndef _to_boolean_mask(values, index):\n    s = pd.Series(values, index=index)\n    if pd.api.types.is_bool_dtype(s):\n        return s.fillna(False).astype(bool)\n    num = pd.to_numeric(s, errors="coerce")\n    if num.notna().any():\n        return num.fillna(0).gt(0).astype(bool)\n    text = s.astype(str).str.strip().str.lower()\n    return text.isin({"1", "true", "t", "yes", "y", "train", "training", "tr"})\n\ndef _infer_train_mask(raw_index, aux):\n    if aux is None or len(aux) == 0:\n        return pd.Series(True, index=raw_index)\n    if len(aux) != len(raw_index):\n        return pd.Series(True, index=raw_index)\n\n    candidates = (\n        "is_train",\n        "is_train_row",\n        "is_train_mask",\n        "is_train_flag",\n        "trainmask",\n        "train_flag",\n        "split",\n        "fold",\n        "set",\n    )\n    col = _find_column(aux.columns, candidates)\n    if col is not None:\n        return pd.Series(\n            _to_boolean_mask(aux[col].to_numpy(), aux.index).to_numpy(),\n            index=raw_index,\n            dtype=bool,\n        )\n    return pd.Series(True, index=raw_index, dtype=bool)\n\ndef _equatorial_to_galactic(ra_deg, dec_deg):\n    ra = pd.to_numeric(ra_deg, errors="coerce").to_numpy(dtype=float)\n    dec = pd.to_numeric(dec_deg, errors="coerce").to_numpy(dtype=float)\n    idx = np.isfinite(ra) & np.isfinite(dec)\n\n    l = np.full(len(ra), np.nan, dtype=float)\n    b = np.full(len(dec), np.nan, dtype=float)\n\n    if idx.any():\n        ra_r = np.radians(ra[idx])\n        dec_r = np.radians(dec[idx])\n\n        cosd = np.cos(dec_r)\n        x = cosd * np.cos(ra_r)\n        y = cosd * np.sin(ra_r)\n        z = np.sin(dec_r)\n\n        m00, m01, m02 = EQ_TO_GAL_MATRIX[0]\n        m10, m11, m12 = EQ_TO_GAL_MATRIX[1]\n        m20, m21, m22 = EQ_TO_GAL_MATRIX[2]\n\n        xg = m00 * x + m01 * y + m02 * z\n        yg = m10 * x + m11 * y + m12 * z\n        zg = m20 * x + m21 * y + m22 * z\n\n        l[idx] = (np.degrees(np.arctan2(yg, xg)) % 360.0)\n        b[idx] = np.degrees(np.arcsin(np.clip(zg, -1.0, 1.0)))\n\n    return pd.Series(l, index=ra_deg.index), pd.Series(b, index=ra_deg.index)\n\ndef _five_deg_bins(l_deg, b_deg):\n    l_arr = np.mod(np.asarray(l_deg, dtype=float), 360.0)\n    b_arr = np.asarray(b_deg, dtype=float)\n\n    l_valid = np.isfinite(l_arr)\n    b_valid = np.isfinite(b_arr)\n\n    l_bin = np.full(len(l_arr), -1, dtype=int)\n    b_bin = np.full(len(b_arr), -1, dtype=int)\n\n    if np.any(l_valid):\n        l_bin[l_valid] = np.floor(l_arr[l_valid] / BIN_SIZE_DEG).astype(int)\n    if np.any(b_valid):\n        b_bin[b_valid] = np.floor((b_arr[b_valid] + 90.0) / BIN_SIZE_DEG).astype(int)\n        b_bin = np.clip(b_bin, 0, 35)\n\n    return pd.Series(l_bin, index=l_deg.index), pd.Series(b_bin, index=b_deg.index)\n\ndef _to_xyz(l_deg, b_deg):\n    l_rad = np.radians(np.asarray(l_deg, dtype=float))\n    b_rad = np.radians(np.asarray(b_deg, dtype=float))\n    cb = np.cos(b_rad)\n    return np.column_stack((cb * np.cos(l_rad), cb * np.sin(l_rad), np.sin(b_rad)))\n\ndef _lookup_map_by_5deg_bins(raw_l, raw_b, map_l, map_b, map_ebv):\n    raw_l_bin, raw_b_bin = _five_deg_bins(raw_l, raw_b)\n\n    map_l = pd.to_numeric(map_l, errors="coerce")\n    map_b = pd.to_numeric(map_b, errors="coerce")\n    map_e = pd.to_numeric(map_ebv, errors="coerce") * SFD98_SCALE\n    valid_map = map_e.notna()\n\n    if valid_map.sum() == 0:\n        return pd.Series(np.nan, index=raw_l.index)\n\n    map_l_bin, map_b_bin = _five_deg_bins(map_l, map_b)\n    map_df = pd.DataFrame(\n        {"l_bin": map_l_bin, "b_bin": map_b_bin, "ebv": map_e},\n        index=map_l.index,\n    )\n    map_df = map_df.loc[valid_map]\n    if len(map_df) == 0:\n        return pd.Series(np.nan, index=raw_l.index)\n\n    map_median = map_df.groupby(["l_bin", "b_bin"], as_index=True)["ebv"].median()\n    lookup_keys = pd.MultiIndex.from_arrays(\n        [raw_l_bin.to_numpy(), raw_b_bin.to_numpy()],\n        names=["l_bin", "b_bin"],\n    )\n    return pd.Series(lookup_keys.map(map_median), index=raw_l.index)\n\ndef _extract_ebv_from_aux(raw_index, aux, raw_l, raw_b):\n    if aux is None or len(aux) == 0:\n        return pd.Series(np.nan, index=raw_index)\n\n    ebv_col = _find_column(\n        aux.columns,\n        (\n            "ebv",\n            "ebv_sfd98",\n            "sfd98_ebv",\n            "sfd_ebv",\n            "ebv_sfd",\n            "sfd",\n            "extinction",\n            "dust",\n        ),\n    )\n    if len(aux) == len(raw_index) and ebv_col is not None:\n        return _to_series(aux[ebv_col], raw_index) * SFD98_SCALE\n\n    l_col = _find_column(\n        aux.columns,\n        ("galacticlongitude", "longitude", "glon", "l", "ldeg", "lon", "ra"),\n    )\n    b_col = _find_column(\n        aux.columns,\n        ("galacticlatitude", "latitude", "glat", "b", "bdeg", "lat"),\n    )\n\n    if ebv_col is None or l_col is None or b_col is None:\n        return pd.Series(np.nan, index=raw_index)\n\n    return _lookup_map_by_5deg_bins(\n        raw_l=raw_l,\n        raw_b=raw_b,\n        map_l=aux[l_col],\n        map_b=aux[b_col],\n        map_ebv=aux[ebv_col],\n    )\n\ndef _nearest_bin_fill(target_bins, median_by_bin):\n    if len(target_bins) == 0:\n        return np.array([], dtype=float)\n    if median_by_bin is None or len(median_by_bin) == 0:\n        return np.full(len(target_bins), np.nan, dtype=float)\n\n    pair_arr = np.asarray(target_bins, dtype=float)\n    out = np.full(len(pair_arr), np.nan, dtype=float)\n\n    full_bins = np.asarray(list(median_by_bin.index), dtype=float)\n    full_vals = np.asarray(median_by_bin.to_numpy(), dtype=float)\n    if full_bins.ndim == 1:\n        full_bins = np.array([full_bins], dtype=float)\n\n    full_mask = (\n        (full_bins[:, 0] >= 0)\n        & (full_bins[:, 0] <= 71.5)\n        & (full_bins[:, 1] >= 0)\n        & (full_bins[:, 1] <= 35.5)\n    )\n    if not full_mask.all():\n        full_bins = full_bins[full_mask]\n        full_vals = full_vals[full_mask]\n\n    if len(full_bins) == 0:\n        return out\n\n    valid = (\n        (pair_arr[:, 0] >= 0)\n        & (pair_arr[:, 0] <= 71.5)\n        & (pair_arr[:, 1] >= 0)\n        & (pair_arr[:, 1] <= 35.5)\n    )\n    if not np.any(valid):\n        return out\n\n    valid_pairs = pair_arr[valid]\n    t_cent = np.column_stack((valid_pairs[:, 0] + 0.5, valid_pairs[:, 1] + 0.5))\n    t_l = t_cent[:, 0] * BIN_SIZE_DEG\n    t_b = t_cent[:, 1] * BIN_SIZE_DEG - 90.0\n    f_cent = np.column_stack((full_bins[:, 0] + 0.5, full_bins[:, 1] + 0.5))\n    f_l = f_cent[:, 0] * BIN_SIZE_DEG\n    f_b = f_cent[:, 1] * BIN_SIZE_DEG - 90.0\n\n    t_vec = _to_xyz(t_l, t_b)\n    f_vec = _to_xyz(f_l, f_b)\n\n    cosang = t_vec @ f_vec.T\n    cosang = np.clip(cosang, -1.0, 1.0)\n    best = np.argmax(cosang, axis=1)\n    best_ang = np.degrees(np.arccos(cosang[np.arange(len(best)), best]))\n    chosen = np.full(len(best), np.nan, dtype=float)\n    near_mask = best_ang <= NEAREST_BIN_MAX_DEG\n    chosen[near_mask] = full_vals[best[near_mask]]\n\n    out[np.where(valid)[0]] = chosen\n    return out\n\ndef _impute_ebv(raw_ebv, raw_l, raw_b, train_mask, index):\n    ebv = _to_series(raw_ebv, index)\n    is_imputed = pd.Series(0, index=index, dtype="int8")\n\n    missing_initial = ~np.isfinite(ebv.to_numpy(dtype=float))\n    if not missing_initial.any():\n        return ebv.clip(EBV_MIN, EBV_MAX), is_imputed\n\n    l_bin, b_bin = _five_deg_bins(raw_l, raw_b)\n    l_arr = l_bin.to_numpy(dtype=int)\n    b_arr = b_bin.to_numpy(dtype=int)\n\n    train_mask = pd.Series(train_mask, index=index, dtype=bool)\n    df = pd.DataFrame(\n        {\n            "l_bin": l_arr,\n            "b_bin": b_arr,\n            "ebv": ebv,\n        },\n        index=index,\n    )\n\n    train_rows = df.loc[train_mask & df["ebv"].notna(), ["l_bin", "b_bin", "ebv"]]\n    if len(train_rows):\n        bin_median = train_rows.groupby(["l_bin", "b_bin"])["ebv"].median()\n    else:\n        bin_median = pd.Series(dtype=float)\n\n    keys = pd.MultiIndex.from_arrays([l_arr, b_arr], names=["l_bin", "b_bin"])\n    key_map = pd.Series(keys.map(bin_median), index=index, dtype=float)\n\n    same_bin_fill = missing_initial & key_map.notna()\n    ebv.loc[same_bin_fill] = key_map.loc[same_bin_fill]\n    is_imputed.loc[same_bin_fill] = 1\n\n    remaining = missing_initial & ebv.isna()\n    if remaining.any():\n        rem_idx = np.where(remaining.to_numpy())[0]\n        rem_pairs = np.unique(\n            np.column_stack((l_arr[rem_idx], b_arr[rem_idx])),\n            axis=0,\n        )\n        rem_vals = _nearest_bin_fill(rem_pairs, bin_median)\n        rem_lookup = {\n            (float(pair[0]), float(pair[1])): val for pair, val in zip(rem_pairs, rem_vals)\n        }\n        rem_filled = np.array(\n            [rem_lookup.get((float(l_arr[i]), float(b_arr[i])), np.nan) for i in rem_idx],\n            dtype=float,\n        )\n        ebv.iloc[rem_idx] = rem_filled\n        is_imputed.iloc[rem_idx] = pd.Series(\n            pd.notna(rem_filled),\n            index=ebv.iloc[rem_idx].index,\n            dtype="int8",\n        ).to_numpy()\n\n    remaining = ebv.isna()\n    if remaining.any():\n        train_valid = df.loc[train_mask & df["ebv"].notna(), "ebv"]\n        if len(train_valid) > 0:\n            global_median = float(pd.to_numeric(train_valid, errors="coerce").median())\n            if not np.isfinite(global_median):\n                global_median = 0.0\n        else:\n            global_median = 0.0\n        ebv.loc[remaining] = global_median\n        is_imputed.loc[remaining] = 1\n\n    return ebv.clip(EBV_MIN, EBV_MAX), is_imputed\n\ndef _latitude_decile_bin(abs_b, train_mask, index):\n    abs_b = pd.to_numeric(abs_b, errors="coerce")\n    train_mask = pd.Series(train_mask, index=index, dtype=bool)\n    train_vals = abs_b.loc[train_mask].to_numpy(dtype=float)\n\n    if not np.isfinite(train_vals).any():\n        train_vals = abs_b.to_numpy(dtype=float)\n\n    finite_train = train_vals[np.isfinite(train_vals)]\n    if finite_train.size == 0:\n        return pd.Series(np.zeros(len(abs_b), dtype="int64"), index=index)\n\n    if np.unique(finite_train).size == 1:\n        return pd.Series(np.zeros(len(abs_b), dtype="int64"), index=index)\n\n    probs = np.linspace(0.0, 1.0, LAT_BIN_COUNT + 1)\n    edges = np.quantile(finite_train, probs)\n    edges_clean = []\n    prev = None\n    for edge in edges:\n        if not np.isfinite(edge):\n            continue\n        edge = float(edge)\n        if prev is None:\n            prev = edge\n            edges_clean.append(edge)\n            continue\n        if edge <= prev:\n            edge = np.nextafter(prev, np.inf)\n        edges_clean.append(edge)\n        prev = edge\n\n    if len(edges_clean) < 2:\n        return pd.Series(np.zeros(len(abs_b), dtype="int64"), index=index)\n\n    edges_clean = np.array(edges_clean, dtype=float)\n    min_v = float(np.nanmin(finite_train))\n    max_v = float(np.nanmax(finite_train))\n    edges_clean[0] = min(min_v, edges_clean[0])\n    edges_clean[-1] = max(max_v, edges_clean[-1])\n\n    if np.any(np.diff(edges_clean) <= 0.0):\n        edges_clean = np.linspace(min_v, max_v, LAT_BIN_COUNT + 1)\n\n    bins = pd.cut(abs_b, bins=edges_clean, include_lowest=True, labels=False)\n    return bins.fillna(-1).astype(int)\n\ndef _clip_continuous_features(features, train_mask):\n    train_mask = pd.Series(train_mask, index=features.index, dtype=bool)\n    numeric_cols = [\n        c\n        for c in features.columns\n        if pd.api.types.is_float_dtype(features[c].dtype)\n    ]\n\n    train_ok = train_mask.copy()\n    if not train_ok.any():\n        train_ok[:] = True\n\n    for col in numeric_cols:\n        vals = pd.to_numeric(features.loc[train_ok, col], errors="coerce")\n        if vals.notna().sum() == 0:\n            continue\n        q = vals.quantile([CLIP_Q_LOW, CLIP_Q_HIGH])\n        lo = float(q.iloc[0])\n        hi = float(q.iloc[1])\n        if np.isfinite(lo) and np.isfinite(hi) and lo < hi:\n            features[col] = features[col].clip(lower=lo, upper=hi)\n\n    return features\n\ndef add_foreground_reddening_geometry(raw, deps, aux):\n    _ = deps\n    index = raw.index\n\n    alpha = _to_series(raw["alpha"], index)\n    delta = _to_series(raw["delta"], index)\n    l_deg, b_deg = _equatorial_to_galactic(alpha, delta)\n\n    train_mask = _infer_train_mask(index, aux)\n\n    ebv_raw = _extract_ebv_from_aux(index, aux, l_deg, b_deg)\n    ebv, is_ebv_imputed = _impute_ebv(ebv_raw, l_deg, b_deg, train_mask, index)\n\n    u = _to_series(raw["u"], index)\n    g = _to_series(raw["g"], index)\n    r = _to_series(raw["r"], index)\n    i = _to_series(raw["i"], index)\n    z = _to_series(raw["z"], index)\n    redshift = _to_series(raw["redshift"], index)\n\n    au, ag, ar, ai, az = EXTINCTION_COEFFS\n\n    u0 = u - au * ebv\n    g0 = g - ag * ebv\n    r0 = r - ar * ebv\n    i0 = i - ai * ebv\n    z0 = z - az * ebv\n\n    color_ug = u - g\n    color_gr = g - r\n    color_ri = r - i\n    color_iz = i - z\n\n    color0_ug = u0 - g0\n    color0_gr = g0 - r0\n    color0_ri = r0 - i0\n    color0_iz = i0 - z0\n\n    c = np.column_stack(\n        [\n            color_ug.to_numpy(dtype=float),\n            color_gr.to_numpy(dtype=float),\n            color_ri.to_numpy(dtype=float),\n            color_iz.to_numpy(dtype=float),\n        ]\n    )\n    c0 = np.column_stack(\n        [\n            color0_ug.to_numpy(dtype=float),\n            color0_gr.to_numpy(dtype=float),\n            color0_ri.to_numpy(dtype=float),\n            color0_iz.to_numpy(dtype=float),\n        ]\n    )\n\n    d = np.array([au - ag, ag - ar, ar - ai, ai - az], dtype=float)\n    dnorm = float(np.linalg.norm(d))\n    if dnorm > 0.0:\n        d_hat = d / dnorm\n    else:\n        d_hat = np.zeros(4, dtype=float)\n\n    t = pd.Series(c.dot(d_hat), index=index)\n    t0 = pd.Series(c0.dot(d_hat), index=index)\n    dt = t - t0\n\n    proj0 = np.outer(t0.to_numpy(dtype=float), d_hat)\n    resid0 = c0 - proj0\n    resid0_0 = pd.Series(resid0[:, 0], index=index)\n    resid0_1 = pd.Series(resid0[:, 1], index=index)\n    resid0_2 = pd.Series(resid0[:, 2], index=index)\n    resid0_norm = pd.Series(np.sqrt(np.sum(resid0 * resid0, axis=1)), index=index)\n\n    abs_b = b_deg.abs()\n    lat_bin = _latitude_decile_bin(abs_b, train_mask, index)\n\n    features = pd.DataFrame(\n        {\n            "ebv_clipped": ebv,\n            "is_ebv_imputed": is_ebv_imputed.astype("int8"),\n            "u0": u0,\n            "g0": g0,\n            "r0": r0,\n            "i0": i0,\n            "z0": z0,\n            "color_ug": color_ug,\n            "color_gr": color_gr,\n            "color_ri": color_ri,\n            "color_iz": color_iz,\n            "color0_ug": color0_ug,\n            "color0_gr": color0_gr,\n            "color0_ri": color0_ri,\n            "color0_iz": color0_iz,\n            "reddening_proj_obs": t,\n            "reddening_proj_dered": t0,\n            "reddening_proj_delta": dt,\n            "reddening_residual0": resid0_0,\n            "reddening_residual1": resid0_1,\n            "reddening_residual2": resid0_2,\n            "reddening_residual_norm": resid0_norm,\n            "gal_b_abs": abs_b,\n            "gal_b_decile_bin": lat_bin,\n            "reddening_delta_times_absb": dt * abs_b,\n            "redshift_times_ebv": redshift * ebv,\n            "ebv_times_absb": ebv * abs_b,\n        },\n        index=index,\n    )\n\n    return _clip_continuous_features(features, train_mask)\n\nFEATURE_GROUPS = [\n    {\n        "name": "foreground_reddening_geometry",\n        "fn": add_foreground_reddening_geometry,\n        "depends_on": [],\n        "description": "Build extinction-aware color geometry features using Galactic E(B-V) with fallback imputation and orthogonal residual decomposition.",\n    },\n]'

HYPOTHESIS_000029_AUTOGLUON_001_PY_59BFE9DCC7_SOURCE = 'import numpy as np\nimport pandas as pd\n\n_LYMAN_BANDS = ("u", "g", "r", "i", "z")\n_LYMAN_WAVELENGTHS = (3551.0, 4686.0, 6165.0, 7481.0, 8931.0)\n_LYMAN_BREAKS = (912.0, 1216.0)\n_EPS = 1e-12\n_MIN_DENOM = 1e-12\n\n\ndef _compute_single_break_features(rest_wavelength, flux_proxy, magnitudes, break_wave):\n    n_rows, n_bands = magnitudes.shape\n    rows = np.arange(n_rows, dtype=np.int64)\n\n    has_edge = rest_wavelength >= break_wave\n    available_mask = np.any(has_edge, axis=1)\n    break_idx = np.where(available_mask, has_edge.argmax(axis=1), n_bands).astype(np.int16)\n    edge_available = ((break_idx > 0) & (break_idx < n_bands)).astype(np.int8)\n\n    jump = np.zeros(n_rows, dtype=np.float64)\n    phase = np.zeros(n_rows, dtype=np.float64)\n    local = np.zeros(n_rows, dtype=np.float64)\n\n    active = edge_available.astype(bool)\n    if np.any(active):\n        active_rows = rows[active]\n        idx = break_idx[active]\n        left_idx = idx - 1\n\n        left_wave = rest_wavelength[active_rows, left_idx]\n        right_wave = rest_wavelength[active_rows, idx]\n        phase_active = (break_wave - left_wave) / (right_wave - left_wave)\n        phase[active_rows] = np.clip(phase_active, 0.0, 1.0)\n\n        left_mag = magnitudes[active_rows, left_idx]\n        right_mag = magnitudes[active_rows, idx]\n        local[active_rows] = left_mag - right_mag\n\n        active_flux = flux_proxy[active_rows]\n        cumsum_flux = np.cumsum(active_flux, axis=1)\n        low_sum = cumsum_flux[np.arange(active_flux.shape[0]), left_idx]\n        high_sum = cumsum_flux[:, -1] - low_sum\n        low_count = idx.astype(np.float64)\n        high_count = float(n_bands) - idx.astype(np.float64)\n\n        low_mean = low_sum / low_count\n        high_mean = high_sum / high_count\n        jump[active_rows] = np.log10((high_mean + _EPS) / (low_mean + _EPS))\n\n    return break_idx, edge_available, jump, phase, local\n\n\ndef add_redshifted_lyman_discontinuity(raw, deps, aux):\n    _ = (deps, aux)\n\n    required_columns = set(_LYMAN_BANDS) | {"redshift"}\n    missing_columns = required_columns - set(raw.columns)\n    if missing_columns:\n        raise KeyError(f"Missing required columns: {sorted(missing_columns)}")\n\n    base = "redshifted_lyman_discontinuity"\n\n    wavelengths = np.asarray(_LYMAN_WAVELENGTHS, dtype=np.float64)\n    z = pd.to_numeric(raw["redshift"], errors="coerce").to_numpy(dtype=np.float64)\n    denom = 1.0 + z\n    denom = np.where(np.isfinite(denom) & (denom > _MIN_DENOM), denom, np.nan)\n\n    mags = raw.loc[:, list(_LYMAN_BANDS)].to_numpy(dtype=np.float64)\n    flux = np.power(10.0, -0.4 * mags)\n    rest = wavelengths[None, :] / denom[:, None]\n\n    features = {}\n\n    for break_wave in _LYMAN_BREAKS:\n        break_idx, edge_available, jump, phase, local = _compute_single_break_features(rest, flux, mags, break_wave)\n        tag = str(int(break_wave))\n\n        features[f"{base}_jump_{tag}"] = pd.Series(jump, index=raw.index, dtype="float64")\n        features[f"{base}_phase_{tag}"] = pd.Series(phase, index=raw.index, dtype="float64")\n        features[f"{base}_local_{tag}"] = pd.Series(local, index=raw.index, dtype="float64")\n        features[f"{base}_break_band_{tag}"] = pd.Series(break_idx, index=raw.index, dtype="int16")\n        features[f"{base}_edge_available_{tag}"] = pd.Series(edge_available, index=raw.index, dtype="int8")\n        features[f"{base}_jump_x_break_band_{tag}"] = pd.Series(\n            jump * break_idx.astype(np.float64), index=raw.index, dtype="float64"\n        )\n        features[f"{base}_local_x_edge_{tag}"] = pd.Series(\n            local * edge_available.astype(np.float64), index=raw.index, dtype="float64"\n        )\n\n    return pd.DataFrame(features, index=raw.index)\n\n\nFEATURE_GROUPS = [\n    {\n        "name": "redshifted_lyman_discontinuity",\n        "fn": add_redshifted_lyman_discontinuity,\n        "depends_on": [],\n        "description": "Compute redshifted Lyman-limit and Lyman-alpha dropout geometry features from ugriz flux proxies and rest-frame band boundaries.",\n    }\n]'

HYPOTHESIS_000035_AUTOGLUON_002_PY_AB6BA372C2_SOURCE = 'import numpy as np\nimport pandas as pd\n\n_BANDS = ("u", "g", "r", "i")\n_BAND_CLIP_QUANTILES = (0.005, 0.995)\n_BAND_CLIP_FALLBACK = (-30.0, 35.0)\n_POCKET_C1_LOW = 0.85\n_POCKET_C1_HIGH = 1.35\n_POCKET_C3_OFFSET = 0.2\n_POCKET_R_LIMIT = 20.5\n_C1_BIN_PROBS = (1.0 / 3.0, 2.0 / 3.0)\n_SOFT_GAP_BIN_PROBS = (0.33, 0.67)\n_CORE_SYMMETRIC_QUANTILE = 0.5\n\n\ndef _to_float(series):\n    values = pd.to_numeric(series, errors="coerce").astype("float64")\n    return values.replace([np.inf, -np.inf], np.nan)\n\n\ndef _clip_band(series):\n    values = _to_float(series)\n    finite = values.dropna()\n    lower, upper = _BAND_CLIP_FALLBACK\n\n    if not finite.empty:\n        q_low = finite.quantile(_BAND_CLIP_QUANTILES[0])\n        q_high = finite.quantile(_BAND_CLIP_QUANTILES[1])\n        if (\n            pd.notna(q_low)\n            and pd.notna(q_high)\n            and np.isfinite(q_low)\n            and np.isfinite(q_high)\n            and q_low < q_high\n        ):\n            lower = float(q_low)\n            upper = float(q_high)\n\n    return values.clip(lower=lower, upper=upper)\n\n\ndef _quantile_tertile_labels(values, q1, q2, labels, fallback_sign=True):\n    index = values.index\n    arr = _to_float(values).to_numpy()\n    result = pd.Series(labels[1], index=index, dtype="object")\n\n    finite = np.isfinite(arr)\n    if finite.any():\n        finite_values = pd.Series(arr[finite])\n        low = finite_values.quantile(q1)\n        high = finite_values.quantile(q2)\n\n        if (\n            pd.notna(low)\n            and pd.notna(high)\n            and np.isfinite(low)\n            and np.isfinite(high)\n            and low < high\n        ):\n            result.loc[arr <= low] = labels[0]\n            result.loc[arr >= high] = labels[2]\n            return result\n\n        if fallback_sign:\n            result.loc[arr < 0.0] = labels[0]\n            result.loc[arr > 0.0] = labels[2]\n\n    result.loc[np.isposinf(arr)] = labels[2]\n    result.loc[np.isneginf(arr)] = labels[0]\n    return result\n\n\ndef _q_core_label(values, quantile, labels):\n    index = values.index\n    arr = _to_float(values).to_numpy()\n    result = pd.Series(labels[1], index=index, dtype="object")\n\n    finite = np.isfinite(arr)\n    if finite.any():\n        finite_abs = pd.Series(np.abs(arr[finite]))\n        threshold = finite_abs.quantile(quantile)\n\n        if pd.notna(threshold) and np.isfinite(threshold) and threshold > 0:\n            result.loc[arr < -threshold] = labels[0]\n            result.loc[arr > threshold] = labels[2]\n            return result\n\n        result.loc[arr < 0.0] = labels[0]\n        result.loc[arr > 0.0] = labels[2]\n        return result\n\n    result.loc[np.isposinf(arr)] = labels[2]\n    result.loc[np.isneginf(arr)] = labels[0]\n    return result\n\n\ndef add_eboss_ptf_c1_c3_geometry(raw, deps, aux):\n    u = _clip_band(raw["u"])\n    g = _clip_band(raw["g"])\n    r = _clip_band(raw["r"])\n    i = _clip_band(raw["i"])\n    r_for_flag = _to_float(raw["r"])\n\n    c_ug = u - g\n    c_gr = g - r\n    c_ri = r - i\n\n    c1 = 0.95 * c_ug + 0.31 * c_gr + 0.11 * c_ri\n    c3 = -0.39 * c_ug + 0.79 * c_gr + 0.47 * c_ri\n\n    d1 = (1.4 - 0.55 * c1) - c3\n    d2 = (0.3 - 0.1 * c1) - c3\n\n    S1 = d1.clip(lower=0.0)\n    S2 = d2.clip(lower=0.0)\n    core = np.minimum(d1, d2)\n    V1 = (-d1).clip(lower=0.0)\n    V2 = (-d2).clip(lower=0.0)\n    soft_gap = np.maximum(V1, V2)\n    normalized_gap = soft_gap.div(1.0 + c1.abs())\n\n    pocket_c1 = pd.Series(\n        np.where(\n            c1 < _POCKET_C1_LOW,\n            _POCKET_C1_LOW - c1,\n            np.where(c1 > _POCKET_C1_HIGH, c1 - _POCKET_C1_HIGH, 0.0),\n        ),\n        index=raw.index,\n        dtype="float64",\n    )\n    pocket_c3 = (-c3 - _POCKET_C3_OFFSET).clip(lower=0.0)\n    pocket_flag = (\n        (r_for_flag < _POCKET_R_LIMIT)\n        & (pocket_c1 <= 1e-12)\n        & (pocket_c3 <= 1e-12)\n    ).astype("int8")\n    pocket_distance = np.maximum(pocket_c1, pocket_c3)\n\n    q_core = _q_core_label(core, _CORE_SYMMETRIC_QUANTILE, ("below", "near", "above"))\n    c1_bin = _quantile_tertile_labels(\n        c1,\n        _C1_BIN_PROBS[0],\n        _C1_BIN_PROBS[1],\n        ("below", "near", "above"),\n        fallback_sign=True,\n    )\n    soft_gap_bin = _quantile_tertile_labels(\n        soft_gap,\n        _SOFT_GAP_BIN_PROBS[0],\n        _SOFT_GAP_BIN_PROBS[1],\n        ("below", "near", "above"),\n        fallback_sign=False,\n    )\n\n    return pd.DataFrame(\n        {\n            "c_ug": c_ug,\n            "c_gr": c_gr,\n            "c_ri": c_ri,\n            "c1": c1,\n            "c3": c3,\n            "d1": d1,\n            "d2": d2,\n            "S1": S1,\n            "S2": S2,\n            "core": core,\n            "V1": V1,\n            "V2": V2,\n            "soft_gap": soft_gap,\n            "normalized_gap": normalized_gap,\n            "pocket_c1": pocket_c1,\n            "pocket_c3": pocket_c3,\n            "pocket_distance": pocket_distance,\n            "pocket_flag": pocket_flag,\n            "q_core": q_core,\n            "c1_bin": c1_bin,\n            "soft_gap_bin": soft_gap_bin,\n        },\n        index=raw.index,\n    )\n\n\nFEATURE_GROUPS = [\n    {\n        "name": "eboss_ptf_c1_c3_geometry",\n        "fn": add_eboss_ptf_c1_c3_geometry,\n        "depends_on": [],\n        "description": "Build robust c1/c3 color-plane wedge geometry features with boundary-separation signals, bright-pocket geometry constraints, and quantile-derived companion bins.",\n    }\n]'

HYPOTHESIS_000040_AUTOGLUON_004_PY_4DB2DBD683_SOURCE = 'import numpy as np\nimport pandas as pd\n\nGROUP_NAME = "class_conditional_color_density_posteriors"\nREDSHIFT_BINS = (-0.01, 0.2, 0.7, 1.3, 2.0, 3.2, 4.8, 7.01)\nIBIN_WIDTH = 0.50\nCOLOR_BIN_COUNT = 16\nCLASS_ALPHA = 1.0\nCLASS_BETA = 0.5\nN_MIN = 200\nEPSILON = 1e-12\n_CHEB_CACHE = {}\n\ndef _to_float_array(values, fallback=0.0):\n    arr = pd.to_numeric(values, errors="coerce").to_numpy(dtype=np.float64)\n    if arr.size == 0:\n        return arr\n    finite = np.isfinite(arr)\n    if np.any(~finite):\n        if np.any(finite):\n            fill = float(np.nanmedian(arr[finite]))\n        else:\n            fill = float(fallback)\n        arr[~finite] = fill\n    return arr\n\ndef _coerce_bool_mask(values):\n    ser = pd.Series(values)\n    if pd.api.types.is_bool_dtype(ser):\n        return ser.fillna(False).astype(bool).to_numpy()\n    if pd.api.types.is_numeric_dtype(ser):\n        return ser.fillna(0).astype(int).astype(bool).to_numpy()\n    lowered = ser.astype("string").str.lower().str.strip().fillna("")\n    return ((lowered == "true") | (lowered == "train") | (lowered == "1") | (lowered == "yes")).to_numpy()\n\ndef _derive_fit_mask(raw, aux):\n    n = len(raw)\n    if n == 0:\n        return np.array([], dtype=bool)\n    if not isinstance(aux, pd.DataFrame) or aux.empty:\n        return np.ones(n, dtype=bool)\n\n    for col in ("is_train", "train", "train_mask", "is_training", "train_row"):\n        if col in aux.columns:\n            if aux[col].notna().any():\n                return _coerce_bool_mask(aux[col])\n\n    for col in ("is_valid", "is_validation", "is_test", "valid", "val"):\n        if col in aux.columns:\n            if aux[col].notna().any():\n                return ~_coerce_bool_mask(aux[col])\n\n    if "split" in aux.columns:\n        split = (\n            aux["split"]\n            .astype("string")\n            .str.lower()\n            .str.strip()\n            .fillna("")\n        )\n        if split.notna().any():\n            return (split == "train").to_numpy()\n\n    return np.ones(n, dtype=bool)\n\ndef _derive_class_indices(raw):\n    n = len(raw)\n    class_idx = np.full(n, 2, dtype=np.int8)  # STAR default\n    if n == 0 or "spectral_type" not in raw.columns:\n        return class_idx\n\n    spectral = raw["spectral_type"].astype("string").str.upper().str.strip().fillna("")\n    class_idx[spectral == "G/K"] = 0  # GALAXY\n    class_idx[spectral == "O/B"] = 1  # QSO\n\n    if "galaxy_population" in raw.columns:\n        galaxy_pop = raw["galaxy_population"].astype("string").str.upper().str.strip().fillna("")\n        class_idx[(spectral == "A/F") & (galaxy_pop == "RED_SEQUENCE")] = 0\n        class_idx[(spectral == "") & (galaxy_pop == "RED_SEQUENCE")] = 0\n\n    return class_idx\n\ndef _assign_redshift_bin(redshift):\n    edges = np.asarray(REDSHIFT_BINS, dtype=np.float64)\n    return np.clip(np.searchsorted(edges, redshift, side="right") - 1, 0, len(edges) - 2)\n\ndef _assign_i_band_bin(i_band, fit_mask):\n    if fit_mask.size == 0 or not np.any(fit_mask):\n        fit_vals = i_band\n    else:\n        fit_vals = i_band[fit_mask]\n\n    finite = np.isfinite(fit_vals)\n    if np.any(finite):\n        i_min = float(np.min(fit_vals[finite]))\n        i_max = float(np.max(fit_vals[finite]))\n    else:\n        finite_global = np.isfinite(i_band)\n        if np.any(finite_global):\n            i_min = float(np.min(i_band[finite_global]))\n            i_max = float(np.max(i_band[finite_global]))\n        else:\n            i_min = 0.0\n            i_max = 0.0\n\n    n_bins = int(np.floor((i_max - i_min) / IBIN_WIDTH)) + 1\n    if n_bins < 1:\n        n_bins = 1\n\n    i_bin = np.floor((i_band - i_min) / IBIN_WIDTH).astype(np.int64)\n    i_bin = np.clip(i_bin, 0, n_bins - 1)\n    return i_bin, n_bins\n\ndef _quantile_with_overflow_bins(values, fit_mask):\n    values_fit = values[fit_mask] if fit_mask.size and np.any(fit_mask) else values\n    finite_fit = np.isfinite(values_fit)\n    if np.any(finite_fit):\n        values_fit = values_fit[finite_fit]\n\n    if values_fit.size == 0:\n        lo = -1.0\n        hi = 1.0\n    else:\n        lo = float(np.nanpercentile(values_fit, 0.5))\n        hi = float(np.nanpercentile(values_fit, 99.5))\n        if not np.isfinite(lo) or not np.isfinite(hi) or (hi <= lo):\n            finite_all = np.isfinite(values)\n            if np.any(finite_all):\n                lo = float(np.min(values[finite_all]))\n                hi = float(np.max(values[finite_all]))\n            if not np.isfinite(lo) or not np.isfinite(hi) or (hi <= lo):\n                lo = 0.0\n                hi = 1.0\n\n    clipped = np.clip(values, lo, hi)\n    quant_probs = np.linspace(0.0, 1.0, COLOR_BIN_COUNT + 1)\n    q = np.quantile(clipped, quant_probs)\n    q = np.asarray(q, dtype=np.float64)\n\n    for i in range(1, q.size):\n        if not np.isfinite(q[i]) or q[i] <= q[i - 1]:\n            q[i] = q[i - 1] + max(1e-12, 1e-9 * (i + 1))\n\n    if q.size < COLOR_BIN_COUNT + 1:\n        q = np.linspace(q[0], q[-1], COLOR_BIN_COUNT + 1)\n\n    return np.concatenate((np.array([-np.inf], dtype=np.float64), q, np.array([np.inf], dtype=np.float64)))\n\ndef _digitize_color(value, edges):\n    bins = len(edges) - 1\n    idx = np.digitize(value, edges[1:-1], right=True)\n    return np.clip(idx, 0, bins - 1).astype(np.int64)\n\ndef _get_chebyshev_neighbors(n_bins):\n    cached = _CHEB_CACHE.get(n_bins)\n    if cached is not None:\n        return cached\n\n    total = n_bins ** 3\n    x = np.arange(total) // (n_bins * n_bins)\n    y = (np.arange(total) // n_bins) % n_bins\n    z = np.arange(total) % n_bins\n\n    n1 = []\n    w1 = []\n    n2 = []\n    w2 = []\n\n    for cx, cy, cz in zip(x, y, z):\n        neigh1 = []\n        weight1 = []\n        neigh2 = []\n        weight2 = []\n        for dx in (-2, -1, 0, 1, 2):\n            nx = cx + dx\n            if nx < 0 or nx >= n_bins:\n                continue\n            for dy in (-2, -1, 0, 1, 2):\n                ny = cy + dy\n                if ny < 0 or ny >= n_bins:\n                    continue\n                for dz in (-2, -1, 0, 1, 2):\n                    nz = cz + dz\n                    if nz < 0 or nz >= n_bins:\n                        continue\n                    r = max(abs(dx), abs(dy), abs(dz))\n                    if r > 2:\n                        continue\n                    cell = (nx * n_bins + ny) * n_bins + nz\n                    weight = 0.5 ** r\n                    neigh2.append(cell)\n                    weight2.append(weight)\n                    if r <= 1:\n                        neigh1.append(cell)\n                        weight1.append(weight)\n\n        n1.append(np.array(neigh1, dtype=np.int32))\n        w1.append(np.array(weight1, dtype=np.float64))\n        n2.append(np.array(neigh2, dtype=np.int32))\n        w2.append(np.array(weight2, dtype=np.float64))\n\n    max1 = max(len(v) for v in n1)\n    max2 = max(len(v) for v in n2)\n\n    neigh1_idx = np.full((total, max1), -1, dtype=np.int32)\n    neigh1_w = np.zeros((total, max1), dtype=np.float64)\n    neigh2_idx = np.full((total, max2), -1, dtype=np.int32)\n    neigh2_w = np.zeros((total, max2), dtype=np.float64)\n\n    for i in range(total):\n        a1 = n1[i]\n        neigh1_idx[i, :len(a1)] = a1\n        neigh1_w[i, :len(a1)] = w1[i]\n\n        a2 = n2[i]\n        neigh2_idx[i, :len(a2)] = a2\n        neigh2_w[i, :len(a2)] = w2[i]\n\n    neigh1_sum = neigh1_w.sum(axis=1)\n    neigh2_sum = neigh2_w.sum(axis=1)\n\n    _CHEB_CACHE[n_bins] = (neigh1_idx, neigh1_w, neigh1_sum, neigh2_idx, neigh2_w, neigh2_sum)\n    return _CHEB_CACHE[n_bins]\n\ndef _weighted_prob_and_mass(class_counts, neigh_idx, neigh_w, neigh_sum):\n    n_strata, n_cells = class_counts.shape\n    totals = class_counts.sum(axis=1)\n    denom = totals + CLASS_ALPHA * n_cells\n    prob = np.zeros((n_strata, n_cells), dtype=np.float64)\n    mass = np.zeros((n_strata, n_cells), dtype=np.float64)\n\n    if n_strata == 0:\n        return prob, mass\n\n    valid = denom > 0\n\n    for cell in range(n_cells):\n        ids = neigh_idx[cell]\n        active = ids >= 0\n        if not np.any(active):\n            continue\n        ids = ids[active].astype(np.int64)\n        weights = neigh_w[cell, active]\n        wsum = neigh_sum[cell]\n        if wsum <= 0:\n            continue\n\n        loc = class_counts[:, ids]\n        mass[:, cell] = np.dot(loc, weights)\n        weighted_num = np.dot(loc + CLASS_ALPHA, weights)\n        if np.any(valid):\n            prob[valid, cell] = (weighted_num[valid] / wsum) / denom[valid]\n\n    return prob, mass\n\ndef add_class_conditional_color_density_posteriors(raw, deps, aux):\n    n = len(raw)\n    index = raw.index\n\n    if n == 0:\n        return pd.DataFrame(index=index)\n\n    required = ("redshift", "u", "g", "r", "i", "spectral_type", "galaxy_population")\n    if any(col not in raw.columns for col in required):\n        zeros = np.zeros(n, dtype=np.float64)\n        return pd.DataFrame(\n            {\n                "s_GALAXY": zeros,\n                "s_QSO": zeros,\n                "s_STAR": zeros,\n                "s_QSO_minus_STAR": zeros,\n                "s_STAR_minus_GALAXY": zeros,\n                "s_entropy": zeros,\n            },\n            index=index,\n        )\n\n    redshift = _to_float_array(raw["redshift"], fallback=0.0)\n    u = _to_float_array(raw["u"], fallback=0.0)\n    g = _to_float_array(raw["g"], fallback=0.0)\n    r = _to_float_array(raw["r"], fallback=0.0)\n    i_band = _to_float_array(raw["i"], fallback=0.0)\n\n    fit_mask = _derive_fit_mask(raw, aux)\n    class_idx = _derive_class_indices(raw)\n\n    red_bin = _assign_redshift_bin(redshift)\n    i_bin, n_i_bins = _assign_i_band_bin(i_band, fit_mask)\n\n    c0 = u - g\n    c1 = g - r\n    c2 = r - i_band\n\n    edges0 = _quantile_with_overflow_bins(c0, fit_mask)\n    edges1 = _quantile_with_overflow_bins(c1, fit_mask)\n    edges2 = _quantile_with_overflow_bins(c2, fit_mask)\n\n    b0 = _digitize_color(c0, edges0)\n    b1 = _digitize_color(c1, edges1)\n    b2 = _digitize_color(c2, edges2)\n\n    n_color_bins = len(edges0) - 1\n    n_color_cells = n_color_bins ** 3\n\n    color_cell = ((b0 * n_color_bins + b1) * n_color_bins + b2).astype(np.int64)\n\n    n_red_bins = len(REDSHIFT_BINS) - 1\n    n_strata = n_red_bins * n_i_bins\n    stratum = red_bin.astype(np.int64) * n_i_bins + i_bin\n\n    class_counts = np.zeros((3, n_strata, n_color_cells), dtype=np.float64)\n\n    for c in range(3):\n        cmask = class_idx == c\n        if not np.any(cmask):\n            continue\n        key = stratum[cmask] * n_color_cells + color_cell[cmask]\n        counts = np.bincount(key, minlength=n_strata * n_color_cells)\n        class_counts[c] = counts.reshape(n_strata, n_color_cells)\n\n    class_tot_by_strata = class_counts.sum(axis=2)\n    total_by_strata = class_tot_by_strata.sum(axis=0)\n\n    pi_strata = np.zeros((3, n_strata), dtype=np.float64)\n    den_pi = total_by_strata + 3.0 * CLASS_BETA\n    valid_pi = den_pi > 0\n    if np.any(valid_pi):\n        pi_strata[:, valid_pi] = (class_tot_by_strata[:, valid_pi] + CLASS_BETA) / den_pi[valid_pi]\n\n    class_tot_global = class_tot_by_strata.sum(axis=1)\n    global_total = class_tot_global.sum()\n    if global_total > 0:\n        pi_global = (class_tot_global + CLASS_BETA) / (global_total + 3.0 * CLASS_BETA)\n    else:\n        pi_global = np.array([1.0 / 3.0] * 3, dtype=np.float64)\n\n    counts_red = class_counts.reshape(3, n_red_bins, n_i_bins, n_color_cells).sum(axis=2)\n\n    p_red = np.zeros_like(counts_red, dtype=np.float64)\n    for c in range(3):\n        row_tot = counts_red[c].sum(axis=1)\n        den_row = row_tot + CLASS_ALPHA * n_color_cells\n        valid_row = den_row > 0\n        if np.any(valid_row):\n            p_red[c, valid_row] = (counts_red[c, valid_row] + CLASS_ALPHA) / den_row[valid_row, None]\n\n    global_counts = class_counts.sum(axis=1)\n    p_global = np.zeros_like(global_counts, dtype=np.float64)\n    for c in range(3):\n        gtot = global_counts[c].sum()\n        if gtot > 0:\n            p_global[c] = (global_counts[c] + CLASS_ALPHA) / (gtot + CLASS_ALPHA * n_color_cells)\n\n    neigh1_idx, neigh1_w, neigh1_sum, neigh2_idx, neigh2_w, neigh2_sum = _get_chebyshev_neighbors(n_color_bins)\n\n    local_prob = []\n    neigh1_prob = []\n    neigh1_mass = []\n    neigh2_prob = []\n    neigh2_mass = []\n\n    for c in range(3):\n        cc = class_counts[c]\n        cc_tot = cc.sum(axis=1)\n        den = cc_tot + CLASS_ALPHA * n_color_cells\n        local = np.zeros((n_strata, n_color_cells), dtype=np.float64)\n        valid = den > 0\n        if np.any(valid):\n            local[valid] = (cc[valid] + CLASS_ALPHA) / den[valid, None]\n\n        p1, m1 = _weighted_prob_and_mass(cc, neigh1_idx, neigh1_w, neigh1_sum)\n        p2, m2 = _weighted_prob_and_mass(cc, neigh2_idx, neigh2_w, neigh2_sum)\n\n        local_prob.append(local)\n        neigh1_prob.append(p1)\n        neigh1_mass.append(m1)\n        neigh2_prob.append(p2)\n        neigh2_mass.append(m2)\n\n    scores = np.zeros((n, 3), dtype=np.float64)\n\n    for c in range(3):\n        class_cell_counts = class_counts[c][stratum, color_cell]\n        class_strata_counts = class_tot_by_strata[c][stratum]\n        strata_counts = total_by_strata[stratum]\n\n        p = local_prob[c][stratum, color_cell]\n        pi = pi_strata[c][stratum]\n\n        use_global_prior = np.zeros(n, dtype=bool)\n        fallback = (strata_counts < N_MIN) | (class_cell_counts <= 0.0) | (class_strata_counts < 1.0)\n\n        if np.any(fallback):\n            m1_row = neigh1_mass[c][stratum, color_cell]\n            p1_row = neigh1_prob[c][stratum, color_cell]\n            can_backoff1 = fallback & (m1_row > 0.0)\n            p[can_backoff1] = p1_row[can_backoff1]\n            fallback = fallback & ~can_backoff1\n\n            if np.any(fallback):\n                m2_row = neigh2_mass[c][stratum, color_cell]\n                p2_row = neigh2_prob[c][stratum, color_cell]\n                can_backoff2 = fallback & (m2_row > 0.0)\n                p[can_backoff2] = p2_row[can_backoff2]\n                fallback = fallback & ~can_backoff2\n\n                if np.any(fallback):\n                    red_counts_row = counts_red[c][red_bin, color_cell]\n                    pz_row = p_red[c][red_bin, color_cell]\n                    can_backoff_red = fallback & (red_counts_row > 0.0)\n                    p[can_backoff_red] = pz_row[can_backoff_red]\n                    fallback = fallback & ~can_backoff_red\n\n                    if np.any(fallback):\n                        global_counts_row = global_counts[c][color_cell]\n                        pg_row = p_global[c][color_cell]\n                        can_backoff_global = fallback & (global_counts_row > 0.0)\n                        p[can_backoff_global] = pg_row[can_backoff_global]\n                        fallback = fallback & ~can_backoff_global\n\n                        if np.any(fallback):\n                            p[fallback] = 1.0\n                            use_global_prior[fallback] = True\n\n        if np.any(use_global_prior):\n            pi[use_global_prior] = pi_global[c]\n\n        scores[:, c] = np.log(np.maximum(pi, EPSILON)) + np.log(np.maximum(p, EPSILON))\n\n    max_score = np.max(scores, axis=1, keepdims=True)\n    exp_score = np.exp(scores - max_score)\n    prob = exp_score / np.maximum(np.sum(exp_score, axis=1, keepdims=True), EPSILON)\n    entropy = -np.sum(prob * np.log(np.maximum(prob, EPSILON)), axis=1) / np.log(3.0)\n\n    return pd.DataFrame(\n        {\n            "s_GALAXY": scores[:, 0],\n            "s_QSO": scores[:, 1],\n            "s_STAR": scores[:, 2],\n            "s_QSO_minus_STAR": scores[:, 1] - scores[:, 2],\n            "s_STAR_minus_GALAXY": scores[:, 2] - scores[:, 0],\n            "s_entropy": entropy,\n        },\n        index=index,\n    )\n\nFEATURE_GROUPS = [\n    {\n        "name": GROUP_NAME,\n        "fn": add_class_conditional_color_density_posteriors,\n        "depends_on": [],\n        "description": "Build redshift- and i-band-conditioned class-conditional color-density posterior scores with deterministic fallback and entropy uncertainty features.",\n    }\n]'

HYPOTHESIS_000056_AUTOGLUON_004_PY_6F54890526_SOURCE = 'import numpy as np\nimport pandas as pd\n\n_CONTEXT_NSIDE = 32\n_REDSHIFT_STRATA = (-np.inf, 0.01, 0.1, 0.3, 0.5, 1.0, 2.0, np.inf)\n_N_STRATA = 7\n_MIN_CONTEXT_COUNT = 60\n_MAD_FLOOR = 1e-6\n_Z_MIN = -8.0\n_Z_MAX = 8.0\n_Q1_COEF = 1.582\n_Q2_COEF = 0.987\n\n\ndef _robust_mad(values):\n    arr = np.asarray(values, dtype=np.float64)\n    arr = arr[~pd.isna(arr)]\n    if arr.size == 0:\n        return np.nan\n    med = np.median(arr)\n    mad = np.median(np.abs(arr - med))\n    return float(mad)\n\n\ndef _fallback_context_and_neighbors(alpha, delta, nside):\n    ra = np.mod(np.asarray(alpha, dtype=np.float64), 360.0)\n    dec = np.asarray(delta, dtype=np.float64)\n\n    n_lon = 4 * nside\n    n_lat = 3 * nside\n\n    lat_edges = np.degrees(np.arcsin(np.linspace(-1.0, 1.0, n_lat + 1)))\n    lon_bin = np.floor((ra / 360.0) * n_lon).astype(np.int64)\n    lon_bin = np.mod(lon_bin, n_lon)\n    lat_bin = np.searchsorted(lat_edges, dec, side="right") - 1\n    lat_bin = np.clip(lat_bin, 0, n_lat - 1)\n\n    context = lat_bin * n_lon + lon_bin\n    context = np.clip(context, 0, n_lon * n_lat - 1).astype(np.int64)\n\n    unique_context = np.unique(context)\n    neighbor_map = {}\n    for ctx in unique_context:\n        lat_idx, lon_idx = divmod(int(ctx), n_lon)\n        neighbors = []\n        for dlat in (-1, 0, 1):\n            lat_n = lat_idx + dlat\n            if 0 <= lat_n < n_lat:\n                for dlon in (-1, 0, 1):\n                    lon_n = (lon_idx + dlon) % n_lon\n                    neighbors.append(lat_n * n_lon + lon_n)\n        neighbor_map[int(ctx)] = np.array(sorted(set(neighbors)), dtype=np.int64)\n    return context, neighbor_map\n\n\ndef _healpix_context_and_neighbors(alpha, delta, nside):\n    import healpy as hp\n\n    ra = np.mod(np.asarray(alpha, dtype=np.float64), 360.0)\n    dec = np.asarray(delta, dtype=np.float64)\n    theta = np.deg2rad(90.0 - np.clip(dec, -90.0, 90.0))\n    phi = np.deg2rad(ra)\n\n    context = hp.ang2pix(nside, theta, phi, nest=False).astype(np.int64)\n    unique_ctx = np.unique(context)\n\n    neighbor_map = {}\n    for ctx in unique_ctx:\n        ctx_i = int(ctx)\n        neigh = hp.get_all_neighbours(nside, ctx_i, nest=False)\n        neigh = np.asarray(neigh, dtype=np.int64)\n        neigh = neigh[neigh >= 0]\n        if neigh.size == 0:\n            neighbor_map[ctx_i] = np.array((ctx_i,), dtype=np.int64)\n        else:\n            neighbor_map[ctx_i] = np.unique(np.concatenate((np.array((ctx_i,), dtype=np.int64), neigh)))\n    return context, neighbor_map\n\n\ndef _context_and_neighbors(alpha, delta, nside):\n    try:\n        return _healpix_context_and_neighbors(alpha, delta, nside)\n    except Exception:\n        return _fallback_context_and_neighbors(alpha, delta, nside)\n\n\ndef add_local_reddening_free_locus_offsets(raw, deps, aux):\n    del deps\n    del aux\n\n    u = raw["u"].to_numpy(dtype=np.float64)\n    g = raw["g"].to_numpy(dtype=np.float64)\n    r = raw["r"].to_numpy(dtype=np.float64)\n    i = raw["i"].to_numpy(dtype=np.float64)\n    z = raw["z"].to_numpy(dtype=np.float64)\n    alpha = raw["alpha"].to_numpy(dtype=np.float64)\n    delta = raw["delta"].to_numpy(dtype=np.float64)\n    redshift = raw["redshift"].to_numpy(dtype=np.float64)\n\n    c_ug = u - g\n    c_gr = g - r\n    c_ri = r - i\n    c_iz = i - z\n    q1 = c_gr - _Q1_COEF * c_ri\n    q2 = c_ri - _Q2_COEF * c_iz\n\n    context, neighbor_map = _context_and_neighbors(alpha, delta, _CONTEXT_NSIDE)\n    context = context.astype(np.int64, copy=False)\n    stratum = np.asarray(\n        pd.cut(\n            redshift,\n            bins=_REDSHIFT_STRATA,\n            labels=False,\n            include_lowest=True,\n            right=False,\n        ),\n        dtype=np.int64,\n    )\n\n    base = pd.DataFrame(\n        {\n            "context": context,\n            "stratum": stratum,\n            "q1": q1,\n            "q2": q2,\n            "c_ug": c_ug,\n            "c_gr": c_gr,\n            "c_ri": c_ri,\n            "c_iz": c_iz,\n        },\n        index=raw.index,\n    )\n    feature_cols = ["q1", "q2", "c_ug", "c_gr", "c_ri", "c_iz"]\n\n    ctx_strat_counts = base.groupby(["context", "stratum"], sort=False).size()\n    ctx_all_counts = base.groupby("context", sort=False).size()\n\n    ctx_strat_count_dict = ctx_strat_counts.to_dict()\n    ctx_all_count_dict = ctx_all_counts.to_dict()\n\n    n = len(base)\n    n_ctx_strat = np.zeros(n, dtype=np.int64)\n    n_ctx_all = np.zeros(n, dtype=np.int64)\n    for row_idx, neigh_cells in enumerate(np.array([neighbor_map[int(c)] for c in context], dtype=object)):\n        s = int(stratum[row_idx])\n        total_strat = 0\n        total_all = 0\n        for neigh in neigh_cells:\n            neigh_i = int(neigh)\n            total_strat += int(ctx_strat_count_dict.get((neigh_i, s), 0))\n            total_all += int(ctx_all_count_dict.get(neigh_i, 0))\n        n_ctx_strat[row_idx] = total_strat\n        n_ctx_all[row_idx] = total_all\n\n    stratum_counts = np.bincount(stratum, minlength=_N_STRATA).astype(np.float64)\n    total_rows = float(n)\n\n    layer_ctx_strat = n_ctx_strat >= _MIN_CONTEXT_COUNT\n    layer_ctx_unstrat = (~layer_ctx_strat) & (n_ctx_all >= _MIN_CONTEXT_COUNT)\n    layer_global = (~layer_ctx_strat) & (~layer_ctx_unstrat)\n    layer_global_strat = layer_global & (stratum_counts[stratum] >= _MIN_CONTEXT_COUNT)\n    layer_global_full = layer_global & (~layer_global_strat)\n\n    strat_med = base.groupby(["context", "stratum"], sort=False)[feature_cols].median()\n    strat_mad = base.groupby(["context", "stratum"], sort=False)[feature_cols].agg(_robust_mad)\n    ctx_med = base.groupby("context", sort=False)[feature_cols].median()\n    ctx_mad = base.groupby("context", sort=False)[feature_cols].agg(_robust_mad)\n    global_strat_med = base.groupby("stratum", sort=False)[feature_cols].median()\n    global_strat_mad = base.groupby("stratum", sort=False)[feature_cols].agg(_robust_mad)\n    global_all_med = base[feature_cols].median()\n    global_all_mad = base[feature_cols].apply(_robust_mad)\n\n    idx = pd.MultiIndex.from_arrays(\n        [pd.Index(context, dtype=np.int64), pd.Index(stratum, dtype=np.int64)],\n        names=("context", "stratum"),\n    )\n\n    out = pd.DataFrame(index=raw.index)\n    for feat in feature_cols:\n        x = base[feat].to_numpy(dtype=np.float64)\n\n        med = np.full(n, float(global_all_med[feat]), dtype=np.float64)\n        mad = np.full(n, float(global_all_mad[feat]), dtype=np.float64)\n\n        med_strat = strat_med[feat].reindex(idx).to_numpy(dtype=np.float64)\n        mad_strat = strat_mad[feat].reindex(idx).to_numpy(dtype=np.float64)\n        med_ctx = ctx_med[feat].reindex(context).to_numpy(dtype=np.float64)\n        mad_ctx = ctx_mad[feat].reindex(context).to_numpy(dtype=np.float64)\n        med_global_strat = global_strat_med[feat].reindex(range(_N_STRATA)).to_numpy(dtype=np.float64)[stratum]\n        mad_global_strat = global_strat_mad[feat].reindex(range(_N_STRATA)).to_numpy(dtype=np.float64)[stratum]\n\n        miss = np.isnan(med_strat)\n        if miss.any():\n            med_strat[miss] = float(global_all_med[feat])\n            mad_strat[miss] = float(global_all_mad[feat])\n\n        miss = np.isnan(med_ctx)\n        if miss.any():\n            med_ctx[miss] = float(global_all_med[feat])\n            mad_ctx[miss] = float(global_all_mad[feat])\n\n        miss = np.isnan(med_global_strat)\n        if miss.any():\n            med_global_strat[miss] = float(global_all_med[feat])\n            mad_global_strat[miss] = float(global_all_mad[feat])\n\n        if layer_ctx_strat.any():\n            loc = np.flatnonzero(layer_ctx_strat)\n            med[loc] = med_strat[loc]\n            mad[loc] = mad_strat[loc]\n\n        if layer_ctx_unstrat.any():\n            loc = np.flatnonzero(layer_ctx_unstrat)\n            med[loc] = med_ctx[loc]\n            mad[loc] = mad_ctx[loc]\n\n        if layer_global_strat.any():\n            loc = np.flatnonzero(layer_global_strat)\n            med[loc] = med_global_strat[loc]\n            mad[loc] = mad_global_strat[loc]\n\n        mad = np.where(np.isfinite(mad) & (mad >= _MAD_FLOOR), mad, _MAD_FLOOR)\n        z = (x - med) / mad\n        out[f"z_{feat}"] = np.clip(z, _Z_MIN, _Z_MAX)\n\n    out["z_locus_deviation"] = np.sqrt(out["z_q1"] ** 2 + out["z_q2"] ** 2)\n\n    counts_df = ctx_strat_counts.reset_index(name="count")\n    logdens_ctx_strat_med = np.full(_N_STRATA, np.log1p(total_rows), dtype=np.float64)\n    logdens_ctx_strat_mad = np.full(_N_STRATA, _MAD_FLOOR, dtype=np.float64)\n    for s in range(_N_STRATA):\n        vals = counts_df.loc[counts_df["stratum"] == s, "count"].to_numpy(dtype=np.float64)\n        if vals.size:\n            lv = np.log1p(vals)\n            med = np.median(lv)\n            mad = np.median(np.abs(lv - med))\n            logdens_ctx_strat_med[s] = med\n            logdens_ctx_strat_mad[s] = mad if mad >= _MAD_FLOOR else _MAD_FLOOR\n        else:\n            logdens_ctx_strat_med[s] = np.log1p(stratum_counts[s])\n\n    log_ctx_counts = np.log1p(ctx_all_counts.to_numpy(dtype=np.float64))\n    logdens_ctx_med = np.median(log_ctx_counts)\n    logdens_ctx_mad = np.median(np.abs(log_ctx_counts - logdens_ctx_med))\n    if not np.isfinite(logdens_ctx_mad) or logdens_ctx_mad < _MAD_FLOOR:\n        logdens_ctx_mad = _MAD_FLOOR\n    logdens_ctx_med_by_strat = np.full(_N_STRATA, logdens_ctx_med, dtype=np.float64)\n    logdens_ctx_mad_by_strat = np.full(_N_STRATA, logdens_ctx_mad, dtype=np.float64)\n\n    logdens_global_strat_med = np.log1p(stratum_counts)\n    logdens_global_strat_mad = np.full(_N_STRATA, _MAD_FLOOR, dtype=np.float64)\n\n    logdens_global_all_med = np.log1p(total_rows)\n    logdens_global_all_mad = _MAD_FLOOR\n\n    log_nctx = np.zeros(n, dtype=np.float64)\n    log_med = np.zeros(n, dtype=np.float64)\n    log_mad = np.zeros(n, dtype=np.float64)\n\n    if layer_ctx_strat.any():\n        loc = np.flatnonzero(layer_ctx_strat)\n        log_nctx[loc] = n_ctx_strat[loc].astype(np.float64)\n        log_med[loc] = logdens_ctx_strat_med[stratum[loc]]\n        log_mad[loc] = logdens_ctx_strat_mad[stratum[loc]]\n\n    if layer_ctx_unstrat.any():\n        loc = np.flatnonzero(layer_ctx_unstrat)\n        log_nctx[loc] = n_ctx_all[loc].astype(np.float64)\n        log_med[loc] = logdens_ctx_med_by_strat[stratum[loc]]\n        log_mad[loc] = logdens_ctx_mad_by_strat[stratum[loc]]\n\n    if layer_global_strat.any():\n        loc = np.flatnonzero(layer_global_strat)\n        log_nctx[loc] = stratum_counts[stratum[loc]]\n        log_med[loc] = logdens_global_strat_med[stratum[loc]]\n        log_mad[loc] = logdens_global_strat_mad[stratum[loc]]\n\n    if layer_global_full.any():\n        loc = np.flatnonzero(layer_global_full)\n        log_nctx[loc] = total_rows\n        log_med[loc] = logdens_global_all_med\n        log_mad[loc] = logdens_global_all_mad\n\n    z_logdens = (np.log1p(log_nctx) - log_med) / np.maximum(log_mad, _MAD_FLOOR)\n    out["z_logdens"] = np.clip(z_logdens, _Z_MIN, _Z_MAX)\n\n    out["context_from_stratified"] = layer_ctx_strat\n    out["context_from_unstratified"] = layer_ctx_unstrat\n    out["context_from_global_fallback"] = layer_global\n\n    return out\n\n\nFEATURE_GROUPS = [\n    {\n        "name": "local_reddening_free_locus_offsets",\n        "fn": add_local_reddening_free_locus_offsets,\n        "depends_on": [],\n        "description": "Builds local reddening-insensitive color residuals by comparing object colors to context-and-redshift robust loci and emits normalized offsets, density offsets, and context fallback indicators.",\n    }\n]'

HYPOTHESIS_000060_AUTOGLUON_001_PY_30E2D1E4AF_SOURCE = 'import numpy as np\nimport pandas as pd\n\n_CLASS_LABELS = ("GALAXY", "QSO", "STAR")\n_REDSHIFT_BINS = (-0.01, 0.1, 0.4, 1.0, 2.0, 2.8, 3.5, 4.5, 7.02)\n_I_BANDS = (17.0, 18.0, 19.0, 20.0, 21.0, 22.0, 23.0, 24.0)\n_ALPHA_SMOOTHING = 30.0\n_BACKOFF_STRENGTH = (80.0, 40.0, 20.0)\n_EPSILON = 1e-6\n_UNKNOWN_TOKEN = "__UNKNOWN__"\n_LABEL_CANDIDATES = ("class", "target", "label", "y", "labels")\n_ID_COL = "id"\n\n\ndef _normalize_class_series(values):\n    if values is None:\n        return pd.Series(dtype="string")\n    s = pd.Series(values).astype("string").str.strip().str.upper()\n    s = s.str.replace(r"[^A-Z/]", "", regex=True)\n    s = s.replace(\n        {\n            "Q": "QSO",\n            "QUASAR": "QSO",\n            "QSO": "QSO",\n            "G": "GALAXY",\n            "GAL": "GALAXY",\n            "GALAXY": "GALAXY",\n            "S": "STAR",\n            "STAR": "STAR",\n        }\n    )\n    return s.where(s.isin(_CLASS_LABELS), pd.NA)\n\n\ndef _build_global_prior(label_series):\n    cleaned = _normalize_class_series(label_series).dropna()\n    if cleaned.empty:\n        return pd.Series(\n            {\n                "GALAXY": 1.0 / len(_CLASS_LABELS),\n                "QSO": 1.0 / len(_CLASS_LABELS),\n                "STAR": 1.0 / len(_CLASS_LABELS),\n            }\n        )\n    counts = cleaned.value_counts().reindex(_CLASS_LABELS, fill_value=0).astype(float)\n    total = float(counts.sum())\n    if total <= 0:\n        return pd.Series(\n            {\n                "GALAXY": 1.0 / len(_CLASS_LABELS),\n                "QSO": 1.0 / len(_CLASS_LABELS),\n                "STAR": 1.0 / len(_CLASS_LABELS),\n            }\n        )\n    return counts / total\n\n\ndef _extract_labels(raw, aux):\n    raw_index = raw.index\n    for label_col in _LABEL_CANDIDATES:\n        if label_col in raw.columns:\n            raw_norm = _normalize_class_series(raw[label_col])\n            if raw_norm.notna().any():\n                return raw_norm, pd.Series(dtype="string")\n\n    if aux is None or not isinstance(aux, pd.DataFrame) or aux.empty:\n        return pd.Series(pd.NA, index=raw_index, dtype="string"), pd.Series(dtype="string")\n\n    aux_pool = pd.Series(dtype="string")\n\n    for label_col in _LABEL_CANDIDATES:\n        if label_col not in aux.columns:\n            continue\n\n        aux_norm = _normalize_class_series(aux[label_col])\n        if not aux_norm.notna().any():\n            continue\n\n        if aux_pool.empty:\n            aux_pool = aux_norm.dropna()\n\n        if _ID_COL in raw.columns and _ID_COL in aux.columns:\n            aux_map_src = aux[[_ID_COL, label_col]].dropna(subset=[label_col])\n            if not aux_map_src.empty:\n                aux_map = pd.Series(\n                    _normalize_class_series(aux_map_src[label_col]).to_numpy(),\n                    index=aux_map_src[_ID_COL].to_numpy(),\n                    dtype="string",\n                )\n                mapped = _normalize_class_series(raw[_ID_COL].map(aux_map))\n                if mapped.notna().any():\n                    return mapped, aux_pool\n\n        if len(aux) == len(raw):\n            candidate = pd.Series(aux_norm.to_numpy(), index=raw_index, dtype="string")\n            if candidate.notna().any():\n                return candidate, aux_pool\n\n    return pd.Series(pd.NA, index=raw_index, dtype="string"), aux_pool\n\n\ndef _build_level_posteriors(source_df, group_cols, global_prior):\n    if source_df.empty:\n        return pd.DataFrame(columns=tuple(_CLASS_LABELS) + ("n",))\n    counts = source_df.groupby(group_cols + ["class"]).size().unstack(fill_value=0)\n    counts = counts.reindex(columns=_CLASS_LABELS, fill_value=0).astype(float)\n    n = counts.sum(axis=1).astype(float)\n    posterior = counts.add(_ALPHA_SMOOTHING * global_prior, axis=1)\n    posterior = posterior.div(n + _ALPHA_SMOOTHING, axis=0)\n    posterior["n"] = n\n    return posterior\n\n\ndef _lookup_level(level_df, row_keys, raw_index, global_prior):\n    if level_df.empty:\n        base = np.tile(global_prior.to_numpy(), (len(raw_index), 1))\n        return pd.DataFrame(base, columns=_CLASS_LABELS, index=raw_index), pd.Series(\n            0.0, index=raw_index\n        )\n\n    aligned = level_df.reindex(row_keys)\n    probs = aligned.reindex(columns=_CLASS_LABELS).copy()\n    probs = probs.fillna({label: float(global_prior[label]) for label in _CLASS_LABELS})\n    counts = aligned.get("n")\n    if not isinstance(counts, pd.Series):\n        counts = pd.Series(0.0, index=row_keys)\n    counts = counts.fillna(0.0).astype(float)\n    probs.index = raw_index\n    counts.index = raw_index\n    return probs, counts\n\n\ndef _global_features(index, global_prior):\n    p = np.tile(global_prior.to_numpy(dtype=float), (len(index), 1))\n    p = np.clip(p, _EPSILON, 1.0 - _EPSILON)\n    logits = np.log((p + _EPSILON) / (1.0 - p + 3.0 * _EPSILON))\n    entropy = -(p * np.log(p)).sum(axis=1)\n    top2 = np.sort(p, axis=1)\n    top2_gap = top2[:, 2] - top2[:, 1]\n\n    return pd.DataFrame(\n        {\n            "class_prior_galaxy": p[:, 0],\n            "class_prior_qso": p[:, 1],\n            "class_prior_star": p[:, 2],\n            "class_logit_margin_galaxy": logits[:, 0],\n            "class_logit_margin_qso": logits[:, 1],\n            "class_logit_margin_star": logits[:, 2],\n            "class_prior_entropy": entropy,\n            "class_top2_gap": top2_gap,\n        },\n        index=index,\n    )\n\n\ndef add_metadata_redshift_magnitude_class_priors(raw, deps, aux):\n    frame = raw\n    index = frame.index\n\n    raw_labels, aux_label_pool = _extract_labels(frame, aux)\n    global_pool = pd.concat([raw_labels.dropna(), aux_label_pool], ignore_index=True)\n    global_prior = _build_global_prior(global_pool)\n\n    required = ("spectral_type", "galaxy_population", "redshift", "i")\n    if any(col not in frame.columns for col in required):\n        return _global_features(index, global_prior)\n\n    spectral = frame["spectral_type"].fillna(_UNKNOWN_TOKEN).astype("string").astype("object")\n    galaxy_population = frame["galaxy_population"].fillna(_UNKNOWN_TOKEN).astype("string").astype("object")\n\n    redshift = pd.to_numeric(frame["redshift"], errors="coerce")\n    i_mag = pd.to_numeric(frame["i"], errors="coerce")\n    redshift = redshift.mask(~redshift.between(-0.05, 7.5))\n    i_mag = i_mag.mask(~i_mag.between(8.0, 31.0))\n\n    red_bins = (float("-inf"),) + _REDSHIFT_BINS + (float("inf"),)\n    i_bins = (float("-inf"),) + _I_BANDS + (float("inf"),)\n\n    red_bin = pd.cut(redshift, bins=red_bins, labels=False, include_lowest=True, right=True).fillna(-1).astype(int)\n    i_bin = pd.cut(i_mag, bins=i_bins, labels=False, include_lowest=True, right=True).fillna(-1).astype(int)\n\n    labeled_mask = raw_labels.notna()\n    train_df = pd.DataFrame(\n        {\n            "spectral_type": spectral.loc[labeled_mask],\n            "galaxy_population": galaxy_population.loc[labeled_mask],\n            "redshift_bin": red_bin.loc[labeled_mask],\n            "i_bin": i_bin.loc[labeled_mask],\n            "class": raw_labels.loc[labeled_mask],\n        },\n        index=index[labeled_mask],\n    )\n\n    level0 = _build_level_posteriors(train_df, ["spectral_type", "galaxy_population", "redshift_bin", "i_bin"], global_prior)\n    level1 = _build_level_posteriors(train_df, ["spectral_type", "galaxy_population", "redshift_bin"], global_prior)\n    level2 = _build_level_posteriors(train_df, ["spectral_type", "galaxy_population"], global_prior)\n\n    keys0 = pd.MultiIndex.from_arrays(\n        [spectral.to_numpy(), galaxy_population.to_numpy(), red_bin.to_numpy(), i_bin.to_numpy()],\n        names=("spectral_type", "galaxy_population", "redshift_bin", "i_bin"),\n    )\n    keys1 = pd.MultiIndex.from_arrays(\n        [spectral.to_numpy(), galaxy_population.to_numpy(), red_bin.to_numpy()],\n        names=("spectral_type", "galaxy_population", "redshift_bin"),\n    )\n    keys2 = pd.MultiIndex.from_arrays(\n        [spectral.to_numpy(), galaxy_population.to_numpy()],\n        names=("spectral_type", "galaxy_population"),\n    )\n\n    p0, n0 = _lookup_level(level0, keys0, index, global_prior)\n    p1, n1 = _lookup_level(level1, keys1, index, global_prior)\n    p2, n2 = _lookup_level(level2, keys2, index, global_prior)\n\n    p0_arr = p0.to_numpy(dtype=float)\n    p1_arr = p1.to_numpy(dtype=float)\n    p2_arr = p2.to_numpy(dtype=float)\n    g_arr = np.tile(global_prior.to_numpy(dtype=float), (len(index), 1))\n\n    n0_arr = n0.to_numpy(dtype=float)\n    n1_arr = n1.to_numpy(dtype=float)\n    n2_arr = n2.to_numpy(dtype=float)\n\n    w0 = np.divide(n0_arr, n0_arr + _BACKOFF_STRENGTH[0], out=np.zeros_like(n0_arr, dtype=float), where=(n0_arr + _BACKOFF_STRENGTH[0]) != 0)\n    w1 = np.divide(n1_arr, n1_arr + _BACKOFF_STRENGTH[1], out=np.zeros_like(n1_arr, dtype=float), where=(n1_arr + _BACKOFF_STRENGTH[1]) != 0)\n    w2 = np.divide(n2_arr, n2_arr + _BACKOFF_STRENGTH[2], out=np.zeros_like(n2_arr, dtype=float), where=(n2_arr + _BACKOFF_STRENGTH[2]) != 0)\n\n    p2_blend = p2_arr * w2[:, None] + g_arr * (1.0 - w2[:, None])\n    p1_blend = p1_arr * w1[:, None] + p2_blend * (1.0 - w1[:, None])\n    p = p0_arr * w0[:, None] + p1_blend * (1.0 - w0[:, None])\n\n    p = np.clip(p, _EPSILON, 1.0 - _EPSILON)\n    margins = np.log((p + _EPSILON) / (1.0 - p + 3.0 * _EPSILON))\n    entropy = -(p * np.log(np.clip(p, _EPSILON, 1.0))).sum(axis=1)\n    sorted_p = np.sort(p, axis=1)\n    top2_gap = sorted_p[:, 2] - sorted_p[:, 1]\n\n    features = pd.DataFrame(\n        {\n            "class_prior_galaxy": p[:, 0],\n            "class_prior_qso": p[:, 1],\n            "class_prior_star": p[:, 2],\n            "class_logit_margin_galaxy": margins[:, 0],\n            "class_logit_margin_qso": margins[:, 1],\n            "class_logit_margin_star": margins[:, 2],\n            "class_prior_entropy": entropy,\n            "class_top2_gap": top2_gap,\n        },\n        index=index,\n    )\n    return features\n\n\nFEATURE_GROUPS = [\n    {\n        "name": "metadata_redshift_magnitude_class_priors",\n        "fn": add_metadata_redshift_magnitude_class_priors,\n        "depends_on": [],\n        "description": "Context anchored class priors in spectral/population/redshift/i-band strata with hierarchical backoff and shrinkage.",\n    }\n]'

